import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area, FunnelChart, Funnel, LabelList
} from 'recharts';
import { 
    Users, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, User as UserIcon, ArrowRight, Target, Info, TrendingUp, AlertTriangle, CircleDashed, History, Zap, Timer
} from 'lucide-react';

interface Props {
    user: User;
}

interface ReportDoc extends Document {
    isVirtual?: boolean;
}

const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#94a3b8',
    'En Proceso': '#3b82f6',
    'Referente': '#a855f7',
    'Control': '#f97316',
    'Terminados': '#22c55e'
};

const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6',
    'FCE': '#f87171',
    'PM': '#facc15',
    'TO BE': '#22c55e'
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const isAnalyst = user.role === UserRole.ANALYST;

    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState(isAnalyst ? user.id : '');
    const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'FLOW'>('OVERVIEW');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];
        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = node.requiredTypes?.length ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];
                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ 
                                    ...realDoc, 
                                    macroprocess: macro, 
                                    process: proc, 
                                    project: proj, 
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false 
                                });
                            } else {
                                unifiedList.push({ 
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`, 
                                    project: proj, 
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name, 
                                    docType: type as DocType, 
                                    state: DocState.NOT_STARTED, 
                                    updatedAt: new Date(0).toISOString(), 
                                    assignees: node.assignees || [], 
                                    isVirtual: true 
                                } as any);
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees?.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    // --- ANÁLISIS DINÁMICO DE FLUJO ---

    const flowMetrics = useMemo(() => {
        const docHistoryMap: Record<string, DocHistory[]> = {};
        // Filtrar historia por los documentos actuales en vista
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));

        history.forEach(h => {
            if (filteredDocIds.has(h.documentId)) {
                if (!docHistoryMap[h.documentId]) docHistoryMap[h.documentId] = [];
                docHistoryMap[h.documentId].push(h);
            }
        });

        const timeInStates: Record<string, number[]> = {};
        let reworks = 0;
        const funnelStates = {
            TOTAL: filteredDocs.length,
            INICIADO: 0,
            REVISION_INTERNA: 0,
            REFERENTE: 0,
            CONTROL: 0,
            APROBADO: 0
        };

        const uniqueDocsInState: Record<string, Set<string>> = {
            INICIADO: new Set(),
            REVISION_INTERNA: new Set(),
            REFERENTE: new Set(),
            CONTROL: new Set(),
            APROBADO: new Set()
        };

        Object.keys(docHistoryMap).forEach(docId => {
            const docHistory = docHistoryMap[docId].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

            for (let i = 0; i < docHistory.length; i++) {
                const entry = docHistory[i];
                const nextEntry = docHistory[i + 1];

                // Mapeo para embudo
                if (entry.newState === DocState.INITIATED) uniqueDocsInState.INICIADO.add(docId);
                if (entry.newState === DocState.INTERNAL_REVIEW) uniqueDocsInState.REVISION_INTERNA.add(docId);
                if (entry.newState === DocState.SENT_TO_REFERENT || entry.newState === DocState.REFERENT_REVIEW) uniqueDocsInState.REFERENTE.add(docId);
                if (entry.newState === DocState.SENT_TO_CONTROL || entry.newState === DocState.CONTROL_REVIEW) uniqueDocsInState.CONTROL.add(docId);
                if (entry.newState === DocState.APPROVED) uniqueDocsInState.APROBADO.add(docId);

                // Cálculo de tiempos
                if (nextEntry) {
                    const start = new Date(entry.timestamp).getTime();
                    const end = new Date(nextEntry.timestamp).getTime();
                    const diffDays = (end - start) / (1000 * 60 * 60 * 24);

                    if (!timeInStates[entry.newState]) timeInStates[entry.newState] = [];
                    timeInStates[entry.newState].push(diffDays);

                    // Detección de re-trabajo (transición a estado previo o rechazo)
                    if (entry.action.toUpperCase().includes('RECHAZO') || entry.action.toUpperCase().includes('RECHAZAR')) {
                        reworks++;
                    }
                }
            }
        });

        const funnelData = [
            { name: 'Universo', value: funnelStates.TOTAL, fill: '#94a3b8' },
            { name: 'Iniciados', value: uniqueDocsInState.INICIADO.size, fill: '#3b82f6' },
            { name: 'Rev. Interna', value: uniqueDocsInState.REVISION_INTERNA.size, fill: '#6366f1' },
            { name: 'Referente', value: uniqueDocsInState.REFERENTE.size, fill: '#a855f7' },
            { name: 'Control', value: uniqueDocsInState.CONTROL.size, fill: '#f97316' },
            { name: 'Aprobados', value: uniqueDocsInState.APROBADO.size, fill: '#22c55e' }
        ];

        const avgTimes = Object.keys(timeInStates).map(state => {
            const avg = timeInStates[state].reduce((a, b) => a + b, 0) / timeInStates[state].length;
            return {
                state: STATE_CONFIG[state as DocState]?.label.split('(')[0].trim() || state,
                avg: parseFloat(avg.toFixed(1))
            };
        }).sort((a, b) => b.avg - a.avg);

        return { funnelData, avgTimes, reworks };
    }, [filteredDocs, history]);

    const kpis = useMemo(() => {
        const now = new Date().getTime();
        const thirtyDaysMs = 30 * 24 * 60 * 60 * 1000;
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED);

        return { 
            total: filteredDocs.length, 
            totalIds: filteredDocs.map(d => d.id),
            approved: approved.length, 
            approvedIds: approved.map(d => d.id),
            reworks: flowMetrics.reworks,
            efficiency: filteredDocs.length > 0 ? Math.round((approved.length / filteredDocs.length) * 100) : 0
        };
    }, [filteredDocs, flowMetrics]);

    const stateData = useMemo(() => {
        const stats = {
            notStarted: { value: 0, ids: [] as string[] },
            inProcess: { value: 0, ids: [] as string[] },
            referent: { value: 0, ids: [] as string[] },
            control: { value: 0, ids: [] as string[] },
            finished: { value: 0, ids: [] as string[] }
        };

        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) {
                stats.notStarted.value++;
                stats.notStarted.ids.push(d.id);
            } else if (d.state === DocState.APPROVED) {
                stats.finished.value++;
                stats.finished.ids.push(d.id);
            } else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) {
                stats.referent.value++;
                stats.referent.ids.push(d.id);
            } else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) {
                stats.control.value++;
                stats.control.ids.push(d.id);
            } else {
                stats.inProcess.value++;
                stats.inProcess.ids.push(d.id);
            }
        });

        return [
          { name: 'No Iniciado', ...stats.notStarted },
          { name: 'En Proceso', ...stats.inProcess },
          { name: 'Referente', ...stats.referent },
          { name: 'Control', ...stats.control },
          { name: 'Terminados', ...stats.finished }
        ];
    }, [filteredDocs]);

    const typeComplianceData = useMemo(() => {
        const types: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];
        return types.map((type) => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const finishedDocs = docsOfType.filter(d => d.state === DocState.APPROVED);
            const percent = docsOfType.length > 0 ? Math.round((finishedDocs.length / docsOfType.length) * 100) : 0;
            return { 
                type, 
                total: docsOfType.length, 
                finished: finishedDocs.length, 
                percent, 
                color: TYPE_COLORS[type],
                finishedIds: finishedDocs.map(d => d.id),
                pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id)
            };
        });
    }, [filteredDocs]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Analizando métricas de flujo...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" /> 
                        Reportes SGD
                    </h1>
                    <p className="text-slate-500">Métricas de desempeño, flujos y eficiencia administrativa.</p>
                </div>
                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))).map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    {!isAnalyst && (
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    )}
                </div>
            </div>

            {/* TABS DE REPORTE */}
            <div className="flex p-1 bg-slate-200/50 rounded-xl w-fit">
                <button 
                    onClick={() => setActiveTab('OVERVIEW')}
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'OVERVIEW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <Target size={16} /> Resumen General
                </button>
                <button 
                    onClick={() => setActiveTab('FLOW')}
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'FLOW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <Zap size={16} /> Dinámica de Flujo
                </button>
            </div>

            <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                <KPICard title="Requeridos" value={kpis.total} icon={FileText} color="indigo" sub="Carga Total" onClick={() => goToDashboard(kpis.totalIds)} canClick={kpis.total > 0} />
                <KPICard title="Tasa Cumplimiento" value={`${kpis.efficiency}%`} icon={Zap} color="green" sub="Avance a Meta" onClick={() => goToDashboard(kpis.approvedIds)} canClick={kpis.approved > 0} />
                <KPICard title="Eventos Re-trabajo" value={kpis.reworks} icon={History} color="amber" sub="Rechazos acumulados" />
                <KPICard title="Días Ciclo Promedio" value={flowMetrics.avgTimes.length > 0 ? (flowMetrics.avgTimes.reduce((a,b) => a+b.avg, 0) / flowMetrics.avgTimes.length).toFixed(1) : '-'} icon={Timer} color="slate" sub="Promedio Global" />
            </div>

            {activeTab === 'OVERVIEW' ? (
                <div className="space-y-6">
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Target size={16} /> Cumplimiento por Tipo</h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                            {typeComplianceData.map((item) => (
                                <div key={item.type} className="flex flex-col items-center">
                                    <div className="relative w-28 h-28 mb-3">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <PieChart>
                                                <Pie 
                                                    data={[
                                                        { name: 'Aprobados', value: item.percent, ids: item.finishedIds, fill: item.color }, 
                                                        { name: 'Pendientes', value: 100 - item.percent, ids: item.pendingIds, fill: '#f1f5f9' }
                                                    ]} 
                                                    cx="50%" cy="50%" innerRadius={35} outerRadius={50} startAngle={90} endAngle={-270} dataKey="value" stroke="none"
                                                    onClick={(data) => data && data.ids && data.ids.length > 0 && goToDashboard(data.ids)}
                                                >
                                                    <Cell key="progress" className="cursor-pointer" />
                                                    <Cell key="bg" className="cursor-pointer" />
                                                </Pie>
                                            </PieChart>
                                        </ResponsiveContainer>
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-lg font-extrabold text-slate-800">{item.percent}%</div>
                                    </div>
                                    <span className="text-xs font-bold text-slate-700 uppercase">{item.type}</span>
                                    <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total} aprobados</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Briefcase size={16} /> Estado del Universo</h3>
                            <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie 
                                            data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={5} dataKey="value"
                                            onClick={(data) => data && data.ids && data.ids.length > 0 && goToDashboard(data.ids)}
                                        >
                                            {stateData.map((entry, index) => <Cell key={index} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} className="cursor-pointer" />)}
                                        </Pie>
                                        <Tooltip />
                                        <Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> Concentración de Carga</h3>
                             <p className="text-xs text-slate-500 mb-6">Visualización de estados para identificar en qué fase se encuentra la mayoría de los documentos.</p>
                             <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={stateData.filter(d => d.name !== 'No Iniciado' && d.name !== 'Terminados')}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                                        <YAxis tick={{fontSize: 10}} />
                                        <Tooltip />
                                        <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="space-y-6">
                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        {/* GRÁFICO DE EMBUDO */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Zap size={16} /> Embudo de Proceso (Conversion)</h3>
                            <p className="text-xs text-slate-500 mb-6">Supervivencia de documentos a través de la cadena de mando institucional.</p>
                            <div className="h-[400px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <FunnelChart>
                                        <Tooltip />
                                        <Funnel dataKey="value" data={flowMetrics.funnelData} isAnimationActive>
                                            <LabelList position="right" fill="#64748b" content={(props: any) => {
                                                const { x, y, width, value, name } = props;
                                                return <text x={x + width + 10} y={y + 15} fill="#475569" fontSize={11} fontWeight="bold">{name}: {value}</text>;
                                            }} />
                                        </Funnel>
                                    </FunnelChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        {/* TIEMPOS DE CICLO */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Timer size={16} /> Tiempos de Ciclo por Etapa</h3>
                             <p className="text-xs text-slate-500 mb-6">Días promedio de permanencia por estado. Valores altos indican cuellos de botella.</p>
                             <div className="h-[400px]">
                                {flowMetrics.avgTimes.length > 0 ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <BarChart data={flowMetrics.avgTimes} layout="vertical" margin={{ left: 40, right: 40 }}>
                                            <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                                            <XAxis type="number" tick={{fontSize: 10}} label={{ value: 'Días', position: 'insideBottom', offset: -5, fontSize: 10 }} />
                                            <YAxis dataKey="state" type="category" tick={{fontSize: 9}} width={120} />
                                            <Tooltip />
                                            <Bar dataKey="avg" name="Días Promedio" fill="#f43f5e" radius={[0, 4, 4, 0]}>
                                                <LabelList dataKey="avg" position="right" fontSize={10} fontWeight="bold" />
                                            </Bar>
                                        </BarChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <div className="h-full flex flex-col items-center justify-center text-slate-400 text-center">
                                        <History size={40} className="mb-2 opacity-20" />
                                        <p className="text-sm italic">Sin datos de transiciones suficientes para calcular promedios.</p>
                                    </div>
                                )}
                             </div>
                        </div>
                    </div>

                    {/* ALERTAS DE EFICIENCIA */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><AlertTriangle size={16} /> Hallazgos de Eficiencia Operativa</h3>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="p-4 bg-red-50 border border-red-100 rounded-lg">
                                <div className="flex items-center gap-2 text-red-700 font-bold mb-2"><History size={16} /> Bucles de Rechazo</div>
                                <p className="text-xs text-red-800">Se han detectado <b>{flowMetrics.reworks}</b> eventos de retroceso en el flujo. Cada retroceso duplica el tiempo de gestión estimado.</p>
                            </div>
                            <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-lg">
                                <div className="flex items-center gap-2 text-indigo-700 font-bold mb-2"><CircleDashed size={16} /> Filtro de Revisión</div>
                                <p className="text-xs text-indigo-800">El <b>{flowMetrics.funnelData.find(d => d.name === 'Rev. Interna')?.value || 0}</b>% de los documentos iniciados logran pasar la revisión interna sin observaciones críticas en el primer intento.</p>
                            </div>
                            <div className="p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                <div className="flex items-center gap-2 text-slate-700 font-bold mb-2"><Timer size={16} /> Estado Más Lento</div>
                                <p className="text-xs text-slate-600">La etapa de <b>{flowMetrics.avgTimes[0]?.state || 'N/A'}</b> presenta el mayor tiempo de respuesta con <b>{flowMetrics.avgTimes[0]?.avg || 0} días</b> promedio.</p>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { 
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', 
        green: 'bg-green-50 text-green-600 border-green-100',
        amber: 'bg-amber-50 text-amber-600 border-amber-100',
        slate: 'bg-slate-50 text-slate-600 border-slate-100'
    };
    return (
        <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md transition-all active:scale-95' : ''}`}>
            <div className="flex justify-between items-start mb-2"><span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={18} /></div>
            <div><span className="text-2xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[10px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={12} className="opacity-60" />}</div></div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, FunnelChart, Funnel, LabelList
} from 'recharts';
import { 
    CheckCircle, FileText, Filter, LayoutDashboard, Briefcase, Loader2, ArrowRight, Target, TrendingUp, AlertTriangle, History, Zap, Timer, BarChart2, Clock
} from 'lucide-react';

interface Props {
    user: User;
}

interface ReportDoc extends Document {
    isVirtual?: boolean;
}

const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#94a3b8',
    'En Proceso': '#3b82f6',
    'Referente': '#a855f7',
    'Control': '#f97316',
    'Terminados': '#22c55e'
};

const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6',
    'FCE': '#f87171',
    'PM': '#facc15',
    'TO BE': '#22c55e'
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const isAnalyst = user.role === UserRole.ANALYST;

    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState(isAnalyst ? user.id : '');
    const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'FLOW'>('OVERVIEW');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];
        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = node.requiredTypes?.length ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];
                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ 
                                    ...realDoc, 
                                    macroprocess: macro, 
                                    process: proc, 
                                    project: proj, 
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false 
                                });
                            } else {
                                unifiedList.push({ 
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`, 
                                    project: proj, 
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name, 
                                    docType: type as DocType, 
                                    state: DocState.NOT_STARTED, 
                                    updatedAt: new Date(0).toISOString(), 
                                    assignees: node.assignees || [], 
                                    isVirtual: true 
                                } as any);
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees?.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    // --- ANÁLISIS DINÁMICO DE FLUJO (DATOS) ---
    const flowMetrics = useMemo(() => {
        const docHistoryMap: Record<string, DocHistory[]> = {};
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));

        history.forEach(h => {
            if (filteredDocIds.has(h.documentId)) {
                if (!docHistoryMap[h.documentId]) docHistoryMap[h.documentId] = [];
                docHistoryMap[h.documentId].push(h);
            }
        });

        const timeInStates: Record<string, number[]> = {};
        let reworks = 0;
        const uniqueDocsInState: Record<string, Set<string>> = {
            INICIADO: new Set(), REVISION_INTERNA: new Set(), REFERENTE: new Set(), CONTROL: new Set(), APROBADO: new Set()
        };

        Object.keys(docHistoryMap).forEach(docId => {
            const docHistory = docHistoryMap[docId].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

            for (let i = 0; i < docHistory.length; i++) {
                const entry = docHistory[i];
                const nextEntry = docHistory[i + 1];

                if (entry.newState === DocState.INITIATED) uniqueDocsInState.INICIADO.add(docId);
                if (entry.newState === DocState.INTERNAL_REVIEW) uniqueDocsInState.REVISION_INTERNA.add(docId);
                if (entry.newState === DocState.SENT_TO_REFERENT || entry.newState === DocState.REFERENT_REVIEW) uniqueDocsInState.REFERENTE.add(docId);
                if (entry.newState === DocState.SENT_TO_CONTROL || entry.newState === DocState.CONTROL_REVIEW) uniqueDocsInState.CONTROL.add(docId);
                if (entry.newState === DocState.APPROVED) uniqueDocsInState.APROBADO.add(docId);

                if (nextEntry) {
                    const start = new Date(entry.timestamp).getTime();
                    const end = new Date(nextEntry.timestamp).getTime();
                    const diffDays = (end - start) / (1000 * 60 * 60 * 24);

                    if (!timeInStates[entry.newState]) timeInStates[entry.newState] = [];
                    timeInStates[entry.newState].push(diffDays);

                    if (entry.action.toUpperCase().includes('RECHAZO') || entry.action.toUpperCase().includes('RECHAZAR')) {
                        reworks++;
                    }
                }
            }
        });

        const funnelData = [
            { name: 'Universo', value: filteredDocs.length, fill: '#94a3b8' },
            { name: 'Iniciados', value: uniqueDocsInState.INICIADO.size, fill: '#3b82f6' },
            { name: 'Rev. Interna', value: uniqueDocsInState.REVISION_INTERNA.size, fill: '#6366f1' },
            { name: 'Referente', value: uniqueDocsInState.REFERENTE.size, fill: '#a855f7' },
            { name: 'Control', value: uniqueDocsInState.CONTROL.size, fill: '#f97316' },
            { name: 'Aprobados', value: uniqueDocsInState.APROBADO.size, fill: '#22c55e' }
        ];

        const avgTimes = Object.keys(timeInStates).map(state => {
            const avg = timeInStates[state].reduce((a, b) => a + b, 0) / timeInStates[state].length;
            return {
                state: STATE_CONFIG[state as DocState]?.label.split('(')[0].trim() || state,
                avg: parseFloat(avg.toFixed(1))
            };
        }).sort((a, b) => b.avg - a.avg);

        return { funnelData, avgTimes, reworks };
    }, [filteredDocs, history]);

    // --- KPIs GENERALES (ESTÁTICOS) ---
    const overviewStats = useMemo(() => {
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const pending = filteredDocs.filter(d => d.state !== DocState.APPROVED && d.state !== DocState.NOT_STARTED);
        const notStarted = filteredDocs.filter(d => d.state === DocState.NOT_STARTED);

        return {
            total: filteredDocs.length,
            totalIds: filteredDocs.map(d => d.id),
            approvedCount: approved.length,
            approvedIds: approved.map(d => d.id),
            pendingCount: pending.length,
            pendingIds: pending.map(d => d.id),
            notStartedCount: notStarted.length,
            notStartedIds: notStarted.map(d => d.id),
            percent: filteredDocs.length > 0 ? Math.round((approved.length / filteredDocs.length) * 100) : 0
        };
    }, [filteredDocs]);

    const stateData = useMemo(() => {
        const stats = {
            notStarted: { value: 0, ids: [] as string[] },
            inProcess: { value: 0, ids: [] as string[] },
            referent: { value: 0, ids: [] as string[] },
            control: { value: 0, ids: [] as string[] },
            finished: { value: 0, ids: [] as string[] }
        };

        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) {
                stats.notStarted.value++;
                stats.notStarted.ids.push(d.id);
            } else if (d.state === DocState.APPROVED) {
                stats.finished.value++;
                stats.finished.ids.push(d.id);
            } else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) {
                stats.referent.value++;
                stats.referent.ids.push(d.id);
            } else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) {
                stats.control.value++;
                stats.control.ids.push(d.id);
            } else {
                stats.inProcess.value++;
                stats.inProcess.ids.push(d.id);
            }
        });

        return [
          { name: 'No Iniciado', ...stats.notStarted },
          { name: 'En Proceso', ...stats.inProcess },
          { name: 'Referente', ...stats.referent },
          { name: 'Control', ...stats.control },
          { name: 'Terminados', ...stats.finished }
        ];
    }, [filteredDocs]);

    const typeComplianceData = useMemo(() => {
        const types: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];
        return types.map((type) => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const finishedDocs = docsOfType.filter(d => d.state === DocState.APPROVED);
            const percent = docsOfType.length > 0 ? Math.round((finishedDocs.length / docsOfType.length) * 100) : 0;
            return { 
                type, total: docsOfType.length, finished: finishedDocs.length, percent, color: TYPE_COLORS[type],
                finishedIds: finishedDocs.map(d => d.id), pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id)
            };
        });
    }, [filteredDocs]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Procesando Reportes...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" /> Reportes Institucionales
                    </h1>
                    <p className="text-slate-500">Métricas de cumplimiento y dinámica operativa del sistema.</p>
                </div>
                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))).map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    {!isAnalyst && (
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    )}
                </div>
            </div>

            {/* TABS DE MODULOS INDEPENDIENTES */}
            <div className="flex p-1 bg-slate-200/50 rounded-xl w-fit">
                <button 
                    onClick={() => setActiveTab('OVERVIEW')}
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'OVERVIEW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <BarChart2 size={16} /> Resumen General
                </button>
                <button 
                    onClick={() => setActiveTab('FLOW')}
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'FLOW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <Zap size={16} /> Dinámica de Flujo
                </button>
            </div>

            {activeTab === 'OVERVIEW' ? (
                <div className="space-y-6 animate-fadeIn">
                    {/* FICHAS ORIGINALES DEL RESUMEN GENERAL */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                        <KPICard title="Total Universo" value={overviewStats.total} icon={FileText} color="indigo" sub="Documentos Definidos" onClick={() => goToDashboard(overviewStats.totalIds)} canClick={overviewStats.total > 0} />
                        <KPICard title="No Iniciados" value={overviewStats.notStartedCount} icon={Clock} color="slate" sub="Pendiente de Carga" onClick={() => goToDashboard(overviewStats.notStartedIds)} canClick={overviewStats.notStartedCount > 0} />
                        <KPICard title="En Gestión" value={overviewStats.pendingCount} icon={TrendingUp} color="amber" sub="En flujo de revisión" onClick={() => goToDashboard(overviewStats.pendingIds)} canClick={overviewStats.pendingCount > 0} />
                        <KPICard title="Aprobados" value={overviewStats.approvedCount} icon={CheckCircle} color="green" sub={`${overviewStats.percent}% de la meta`} onClick={() => goToDashboard(overviewStats.approvedIds)} canClick={overviewStats.approvedCount > 0} />
                    </div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Target size={16} /> Cumplimiento por Tipo de Documento</h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                            {typeComplianceData.map((item) => (
                                <div key={item.type} className="flex flex-col items-center">
                                    <div className="relative w-28 h-28 mb-3">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <PieChart>
                                                <Pie 
                                                    data={[
                                                        { name: 'Aprobados', value: item.percent, ids: item.finishedIds, fill: item.color }, 
                                                        { name: 'Pendientes', value: 100 - item.percent, ids: item.pendingIds, fill: '#f1f5f9' }
                                                    ]} 
                                                    cx="50%" cy="50%" innerRadius={35} outerRadius={50} startAngle={90} endAngle={-270} dataKey="value" stroke="none"
                                                    onClick={(data) => data && data.ids && data.ids.length > 0 && goToDashboard(data.ids)}
                                                >
                                                    <Cell key="progress" className="cursor-pointer" />
                                                    <Cell key="bg" className="cursor-pointer" />
                                                </Pie>
                                            </PieChart>
                                        </ResponsiveContainer>
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-lg font-extrabold text-slate-800">{item.percent}%</div>
                                    </div>
                                    <span className="text-xs font-bold text-slate-700 uppercase">{item.type}</span>
                                    <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total} aprobados</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Briefcase size={16} /> Distribución por Estado</h3>
                            <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie 
                                            data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={5} dataKey="value"
                                            onClick={(data) => data && data.ids && data.ids.length > 0 && goToDashboard(data.ids)}
                                        >
                                            {stateData.map((entry, index) => <Cell key={index} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} className="cursor-pointer" />)}
                                        </Pie>
                                        <Tooltip />
                                        <Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> Concentración de Carga Operativa</h3>
                             <p className="text-xs text-slate-500 mb-6">Documentos activos por fase de revisión (Excluye No Iniciados y Terminados).</p>
                             <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={stateData.filter(d => d.name !== 'No Iniciado' && d.name !== 'Terminados')}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                                        <YAxis tick={{fontSize: 10}} />
                                        <Tooltip />
                                        <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="space-y-6 animate-fadeIn">
                    {/* FICHAS DE DINAMICA DE FLUJO */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                        <KPICard title="Requeridos" value={overviewStats.total} icon={FileText} color="indigo" sub="Universo a procesar" />
                        <KPICard title="Tasa Cumplimiento" value={`${overviewStats.percent}%`} icon={Zap} color="green" sub="Avance real" />
                        <KPICard title="Eventos Re-trabajo" value={flowMetrics.reworks} icon={History} color="amber" sub="Rechazos detectados" />
                        <KPICard title="Días Ciclo Prom." value={flowMetrics.avgTimes.length > 0 ? (flowMetrics.avgTimes.reduce((a,b) => a+b.avg, 0) / flowMetrics.avgTimes.length).toFixed(1) : '-'} icon={Timer} color="slate" sub="Respuesta Global" />
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        {/* EMBUDO */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Zap size={16} /> Embudo de Conversión (Survival)</h3>
                            <p className="text-xs text-slate-500 mb-6">Cantidad de documentos que logran avanzar a través de cada etapa del proceso.</p>
                            <div className="h-[400px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <FunnelChart>
                                        <Tooltip />
                                        <Funnel dataKey="value" data={flowMetrics.funnelData} isAnimationActive>
                                            <LabelList position="right" fill="#64748b" content={(props: any) => {
                                                const { x, y, width, value, name } = props;
                                                return <text x={x + width + 10} y={y + 15} fill="#475569" fontSize={11} fontWeight="bold">{name}: {value}</text>;
                                            }} />
                                        </Funnel>
                                    </FunnelChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        {/* TIEMPOS DE CICLO */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Timer size={16} /> Tiempos de Ciclo por Etapa</h3>
                             <p className="text-xs text-slate-500 mb-6">Días promedio que un documento permanece en cada estado (Identificación de Cuellos de Botella).</p>
                             <div className="h-[400px]">
                                {flowMetrics.avgTimes.length > 0 ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <BarChart data={flowMetrics.avgTimes} layout="vertical" margin={{ left: 40, right: 40 }}>
                                            <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                                            <XAxis type="number" tick={{fontSize: 10}} label={{ value: 'Días', position: 'insideBottom', offset: -5, fontSize: 10 }} />
                                            <YAxis dataKey="state" type="category" tick={{fontSize: 9}} width={120} />
                                            <Tooltip />
                                            <Bar dataKey="avg" name="Días Promedio" fill="#f43f5e" radius={[0, 4, 4, 0]}>
                                                <LabelList dataKey="avg" position="right" fontSize={10} fontWeight="bold" />
                                            </Bar>
                                        </BarChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <div className="h-full flex flex-col items-center justify-center text-slate-400 text-center">
                                        <History size={40} className="mb-2 opacity-20" />
                                        <p className="text-sm italic">Datos insuficientes para calcular ciclos de vida.</p>
                                    </div>
                                )}
                             </div>
                        </div>
                    </div>

                    {/* HALLAZGOS DE EFICIENCIA */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><AlertTriangle size={16} /> Hallazgos de Eficiencia Operativa</h3>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="p-4 bg-red-50 border border-red-100 rounded-lg">
                                <div className="flex items-center gap-2 text-red-700 font-bold mb-2"><History size={16} /> Rechazos Acumulados</div>
                                <p className="text-xs text-red-800">Se han contabilizado <b>{flowMetrics.reworks}</b> eventos de retroceso. Esto sugiere necesidad de revisar criterios de calidad inicial.</p>
                            </div>
                            <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-lg">
                                <div className="flex items-center gap-2 text-indigo-700 font-bold mb-2"><CircleDashed size={16} /> Filtro de Conversión</div>
                                <p className="text-xs text-indigo-800">Cerca del <b>{flowMetrics.funnelData.find(d => d.name === 'Rev. Interna')?.value || 0}</b>% de los procesos iniciados logran superar la primera barrera de control.</p>
                            </div>
                            <div className="p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                <div className="flex items-center gap-2 text-slate-700 font-bold mb-2"><Timer size={16} /> Puntos Críticos</div>
                                <p className="text-xs text-slate-600">La fase de <b>{flowMetrics.avgTimes[0]?.state || 'N/A'}</b> es la más lenta, consumiendo <b>{flowMetrics.avgTimes[0]?.avg || 0} días</b> promedio.</p>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { 
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', 
        green: 'bg-green-50 text-green-600 border-green-100',
        amber: 'bg-amber-50 text-amber-600 border-amber-100',
        slate: 'bg-slate-50 text-slate-600 border-slate-100'
    };
    return (
        <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md transition-all active:scale-95' : ''}`}>
            <div className="flex justify-between items-start mb-2"><span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={18} /></div>
            <div><span className="text-2xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[10px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={12} className="opacity-60" />}</div></div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, FunnelChart, Funnel, LabelList
} from 'recharts';
import { 
    CheckCircle, FileText, Filter, LayoutDashboard, Briefcase, Loader2, ArrowRight, Target, TrendingUp, AlertTriangle, History, Zap, Timer, BarChart2, Clock, CircleDashed
} from 'lucide-react';

interface Props {
    user: User;
}

interface ReportDoc extends Document {
    isVirtual?: boolean;
}

const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#94a3b8',
    'En Proceso': '#3b82f6',
    'Referente': '#a855f7',
    'Control': '#f97316',
    'Terminados': '#22c55e'
};

const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6',
    'FCE': '#f87171',
    'PM': '#facc15',
    'TO BE': '#22c55e'
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const isAnalyst = user.role === UserRole.ANALYST;

    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState(isAnalyst ? user.id : '');
    const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'FLOW'>('OVERVIEW');

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];
        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;

                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = node.requiredTypes?.length ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];
                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ 
                                    ...realDoc, 
                                    macroprocess: macro, 
                                    process: proc, 
                                    project: proj, 
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false 
                                });
                            } else {
                                unifiedList.push({ 
                                    id: `virtual-${key}`, 
                                    title: `${node.name} - ${type}`, 
                                    project: proj, 
                                    macroprocess: macro,
                                    process: proc,
                                    microprocess: node.name, 
                                    docType: type as DocType, 
                                    state: DocState.NOT_STARTED, 
                                    updatedAt: new Date(0).toISOString(), 
                                    assignees: node.assignees || [], 
                                    isVirtual: true 
                                } as any);
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees?.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    // --- ANÁLISIS DINÁMICO DE FLUJO (DATOS) ---
    const flowMetrics = useMemo(() => {
        const docHistoryMap: Record<string, DocHistory[]> = {};
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));

        history.forEach(h => {
            if (filteredDocIds.has(h.documentId)) {
                if (!docHistoryMap[h.documentId]) docHistoryMap[h.documentId] = [];
                docHistoryMap[h.documentId].push(h);
            }
        });

        const timeInStates: Record<string, number[]> = {};
        let reworks = 0;
        const uniqueDocsInState: Record<string, Set<string>> = {
            INICIADO: new Set(), REVISION_INTERNA: new Set(), REFERENTE: new Set(), CONTROL: new Set(), APROBADO: new Set()
        };

        Object.keys(docHistoryMap).forEach(docId => {
            const docHistory = docHistoryMap[docId].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());

            for (let i = 0; i < docHistory.length; i++) {
                const entry = docHistory[i];
                const nextEntry = docHistory[i + 1];

                if (entry.newState === DocState.INITIATED) uniqueDocsInState.INICIADO.add(docId);
                if (entry.newState === DocState.INTERNAL_REVIEW) uniqueDocsInState.REVISION_INTERNA.add(docId);
                if (entry.newState === DocState.SENT_TO_REFERENT || entry.newState === DocState.REFERENT_REVIEW) uniqueDocsInState.REFERENTE.add(docId);
                if (entry.newState === DocState.SENT_TO_CONTROL || entry.newState === DocState.CONTROL_REVIEW) uniqueDocsInState.CONTROL.add(docId);
                if (entry.newState === DocState.APPROVED) uniqueDocsInState.APROBADO.add(docId);

                if (nextEntry) {
                    const start = new Date(entry.timestamp).getTime();
                    const end = new Date(nextEntry.timestamp).getTime();
                    const diffDays = (end - start) / (1000 * 60 * 60 * 24);

                    if (!timeInStates[entry.newState]) timeInStates[entry.newState] = [];
                    timeInStates[entry.newState].push(diffDays);

                    if (entry.action.toUpperCase().includes('RECHAZO') || entry.action.toUpperCase().includes('RECHAZAR')) {
                        reworks++;
                    }
                }
            }
        });

        const funnelData = [
            { name: 'Universo', value: filteredDocs.length, fill: '#94a3b8' },
            { name: 'Iniciados', value: uniqueDocsInState.INICIADO.size, fill: '#3b82f6' },
            { name: 'Rev. Interna', value: uniqueDocsInState.REVISION_INTERNA.size, fill: '#6366f1' },
            { name: 'Referente', value: uniqueDocsInState.REFERENTE.size, fill: '#a855f7' },
            { name: 'Control', value: uniqueDocsInState.CONTROL.size, fill: '#f97316' },
            { name: 'Aprobados', value: uniqueDocsInState.APROBADO.size, fill: '#22c55e' }
        ];

        const avgTimes = Object.keys(timeInStates).map(state => {
            const avg = timeInStates[state].reduce((a, b) => a + b, 0) / timeInStates[state].length;
            return {
                state: STATE_CONFIG[state as DocState]?.label.split('(')[0].trim() || state,
                avg: parseFloat(avg.toFixed(1))
            };
        }).sort((a, b) => b.avg - a.avg);

        return { funnelData, avgTimes, reworks };
    }, [filteredDocs, history]);

    // --- KPIs GENERALES (ESTÁTICOS) ---
    const overviewStats = useMemo(() => {
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const pending = filteredDocs.filter(d => d.state !== DocState.APPROVED && d.state !== DocState.NOT_STARTED);
        const notStarted = filteredDocs.filter(d => d.state === DocState.NOT_STARTED);

        return {
            total: filteredDocs.length,
            totalIds: filteredDocs.map(d => d.id),
            approvedCount: approved.length,
            approvedIds: approved.map(d => d.id),
            pendingCount: pending.length,
            pendingIds: pending.map(d => d.id),
            notStartedCount: notStarted.length,
            notStartedIds: notStarted.map(d => d.id),
            percent: filteredDocs.length > 0 ? Math.round((approved.length / filteredDocs.length) * 100) : 0
        };
    }, [filteredDocs]);

    const stateData = useMemo(() => {
        const stats = {
            notStarted: { value: 0, ids: [] as string[] },
            inProcess: { value: 0, ids: [] as string[] },
            referent: { value: 0, ids: [] as string[] },
            control: { value: 0, ids: [] as string[] },
            finished: { value: 0, ids: [] as string[] }
        };

        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) {
                stats.notStarted.value++;
                stats.notStarted.ids.push(d.id);
            } else if (d.state === DocState.APPROVED) {
                stats.finished.value++;
                stats.finished.ids.push(d.id);
            } else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) {
                stats.referent.value++;
                stats.referent.ids.push(d.id);
            } else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) {
                stats.control.value++;
                stats.control.ids.push(d.id);
            } else {
                stats.inProcess.value++;
                stats.inProcess.ids.push(d.id);
            }
        });

        return [
          { name: 'No Iniciado', ...stats.notStarted },
          { name: 'En Proceso', ...stats.inProcess },
          { name: 'Referente', ...stats.referent },
          { name: 'Control', ...stats.control },
          { name: 'Terminados', ...stats.finished }
        ];
    }, [filteredDocs]);

    const typeComplianceData = useMemo(() => {
        const types: DocType[] = ['AS IS', 'FCE', 'PM', 'TO BE'];
        return types.map((type) => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const finishedDocs = docsOfType.filter(d => d.state === DocState.APPROVED);
            const percent = docsOfType.length > 0 ? Math.round((finishedDocs.length / docsOfType.length) * 100) : 0;
            return { 
                type, total: docsOfType.length, finished: finishedDocs.length, percent, color: TYPE_COLORS[type],
                finishedIds: finishedDocs.map(d => d.id), pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id)
            };
        });
    }, [filteredDocs]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Procesando Reportes...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" /> Reportes Institucionales
                    </h1>
                    <p className="text-slate-500">Métricas de cumplimiento y dinámica operativa del sistema.</p>
                </div>
                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))).map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    {!isAnalyst && (
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    )}
                </div>
            </div>

            {/* TABS DE MODULOS INDEPENDIENTES */}
            <div className="flex p-1 bg-slate-200/50 rounded-xl w-fit">
                <button 
                    onClick={() => setActiveTab('OVERVIEW')}
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'OVERVIEW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <BarChart2 size={16} /> Resumen General
                </button>
                <button 
                    onClick={() => setActiveTab('FLOW')}
                    className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'FLOW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
                >
                    <Zap size={16} /> Dinámica de Flujo
                </button>
            </div>

            {activeTab === 'OVERVIEW' ? (
                <div className="space-y-6 animate-fadeIn">
                    {/* FICHAS ORIGINALES DEL RESUMEN GENERAL */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                        <KPICard title="Total Universo" value={overviewStats.total} icon={FileText} color="indigo" sub="Documentos Definidos" onClick={() => goToDashboard(overviewStats.totalIds)} canClick={overviewStats.total > 0} />
                        <KPICard title="No Iniciados" value={overviewStats.notStartedCount} icon={Clock} color="slate" sub="Pendiente de Carga" onClick={() => goToDashboard(overviewStats.notStartedIds)} canClick={overviewStats.notStartedCount > 0} />
                        <KPICard title="En Gestión" value={overviewStats.pendingCount} icon={TrendingUp} color="amber" sub="En flujo de revisión" onClick={() => goToDashboard(overviewStats.pendingIds)} canClick={overviewStats.pendingCount > 0} />
                        <KPICard title="Aprobados" value={overviewStats.approvedCount} icon={CheckCircle} color="green" sub={`${overviewStats.percent}% de la meta`} onClick={() => goToDashboard(overviewStats.approvedIds)} canClick={overviewStats.approvedCount > 0} />
                    </div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Target size={16} /> Cumplimiento por Tipo de Documento</h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                            {typeComplianceData.map((item) => (
                                <div key={item.type} className="flex flex-col items-center">
                                    <div className="relative w-28 h-28 mb-3">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <PieChart>
                                                <Pie 
                                                    data={[
                                                        { name: 'Aprobados', value: item.percent, ids: item.finishedIds, fill: item.color }, 
                                                        { name: 'Pendientes', value: 100 - item.percent, ids: item.pendingIds, fill: '#f1f5f9' }
                                                    ]} 
                                                    cx="50%" cy="50%" innerRadius={35} outerRadius={50} startAngle={90} endAngle={-270} dataKey="value" stroke="none"
                                                    onClick={(data) => data && data.ids && data.ids.length > 0 && goToDashboard(data.ids)}
                                                >
                                                    <Cell key="progress" className="cursor-pointer" />
                                                    <Cell key="bg" className="cursor-pointer" />
                                                </Pie>
                                            </PieChart>
                                        </ResponsiveContainer>
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-lg font-extrabold text-slate-800">{item.percent}%</div>
                                    </div>
                                    <span className="text-xs font-bold text-slate-700 uppercase">{item.type}</span>
                                    <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total} aprobados</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Briefcase size={16} /> Distribución por Estado</h3>
                            <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie 
                                            data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={90} paddingAngle={5} dataKey="value"
                                            onClick={(data) => data && data.ids && data.ids.length > 0 && goToDashboard(data.ids)}
                                        >
                                            {stateData.map((entry, index) => <Cell key={index} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} className="cursor-pointer" />)}
                                        </Pie>
                                        <Tooltip />
                                        <Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> Concentración de Carga Operativa</h3>
                             <p className="text-xs text-slate-500 mb-6">Documentos activos por fase de revisión (Excluye No Iniciados y Terminados).</p>
                             <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={stateData.filter(d => d.name !== 'No Iniciado' && d.name !== 'Terminados')}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                                        <YAxis tick={{fontSize: 10}} />
                                        <Tooltip />
                                        <Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="space-y-6 animate-fadeIn">
                    {/* FICHAS DE DINAMICA DE FLUJO */}
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                        <KPICard title="Requeridos" value={overviewStats.total} icon={FileText} color="indigo" sub="Universo a procesar" />
                        <KPICard title="Tasa Cumplimiento" value={`${overviewStats.percent}%`} icon={Zap} color="green" sub="Avance real" />
                        <KPICard title="Eventos Re-trabajo" value={flowMetrics.reworks} icon={History} color="amber" sub="Rechazos detectados" />
                        <KPICard title="Días Ciclo Prom." value={flowMetrics.avgTimes.length > 0 ? (flowMetrics.avgTimes.reduce((a,b) => a+b.avg, 0) / flowMetrics.avgTimes.length).toFixed(1) : '-'} icon={Timer} color="slate" sub="Respuesta Global" />
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        {/* EMBUDO */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Zap size={16} /> Embudo de Conversión (Survival)</h3>
                            <p className="text-xs text-slate-500 mb-6">Cantidad de documentos que logran avanzar a través de cada etapa del proceso.</p>
                            <div className="h-[400px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <FunnelChart>
                                        <Tooltip />
                                        <Funnel dataKey="value" data={flowMetrics.funnelData} isAnimationActive>
                                            <LabelList position="right" fill="#64748b" content={(props: any) => {
                                                const { x, y, width, value, name } = props;
                                                return <text x={x + width + 10} y={y + 15} fill="#475569" fontSize={11} fontWeight="bold">{name}: {value}</text>;
                                            }} />
                                        </Funnel>
                                    </FunnelChart>
                                </ResponsiveContainer>
                            </div>
                        </div>

                        {/* TIEMPOS DE CICLO */}
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Timer size={16} /> Tiempos de Ciclo por Etapa</h3>
                             <p className="text-xs text-slate-500 mb-6">Días promedio que un documento permanece en cada estado (Identificación de Cuellos de Botella).</p>
                             <div className="h-[400px]">
                                {flowMetrics.avgTimes.length > 0 ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <BarChart data={flowMetrics.avgTimes} layout="vertical" margin={{ left: 40, right: 40 }}>
                                            <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                                            <XAxis type="number" tick={{fontSize: 10}} label={{ value: 'Días', position: 'insideBottom', offset: -5, fontSize: 10 }} />
                                            <YAxis dataKey="state" type="category" tick={{fontSize: 9}} width={120} />
                                            <Tooltip />
                                            <Bar dataKey="avg" name="Días Promedio" fill="#f43f5e" radius={[0, 4, 4, 0]}>
                                                <LabelList dataKey="avg" position="right" fontSize={10} fontWeight="bold" />
                                            </Bar>
                                        </BarChart>
                                    </ResponsiveContainer>
                                ) : (
                                    <div className="h-full flex flex-col items-center justify-center text-slate-400 text-center">
                                        <History size={40} className="mb-2 opacity-20" />
                                        <p className="text-sm italic">Datos insuficientes para calcular ciclos de vida.</p>
                                    </div>
                                )}
                             </div>
                        </div>
                    </div>

                    {/* HALLAZGOS DE EFICIENCIA */}
                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><AlertTriangle size={16} /> Hallazgos de Eficiencia Operativa</h3>
                        <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                            <div className="p-4 bg-red-50 border border-red-100 rounded-lg">
                                <div className="flex items-center gap-2 text-red-700 font-bold mb-2"><History size={16} /> Rechazos Acumulados</div>
                                <p className="text-xs text-red-800">Se han contabilizado <b>{flowMetrics.reworks}</b> eventos de retroceso. Esto sugiere necesidad de revisar criterios de calidad inicial.</p>
                            </div>
                            <div className="p-4 bg-indigo-50 border border-indigo-100 rounded-lg">
                                <div className="flex items-center gap-2 text-indigo-700 font-bold mb-2"><CircleDashed size={16} /> Filtro de Conversión</div>
                                <p className="text-xs text-indigo-800">Cerca del <b>{flowMetrics.funnelData.find(d => d.name === 'Rev. Interna')?.value || 0}</b>% de los procesos iniciados logran superar la primera barrera de control.</p>
                            </div>
                            <div className="p-4 bg-slate-50 border border-slate-200 rounded-lg">
                                <div className="flex items-center gap-2 text-slate-700 font-bold mb-2"><Timer size={16} /> Puntos Críticos</div>
                                <p className="text-xs text-slate-600">La fase de <b>{flowMetrics.avgTimes[0]?.state || 'N/A'}</b> es la más lenta, consumiendo <b>{flowMetrics.avgTimes[0]?.avg || 0} días</b> promedio.</p>
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { 
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', 
        green: 'bg-green-50 text-green-600 border-green-100',
        amber: 'bg-amber-50 text-amber-600 border-amber-100',
        slate: 'bg-slate-50 text-slate-600 border-slate-100'
    };
    return (
        <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md transition-all active:scale-95' : ''}`}>
            <div className="flex justify-between items-start mb-2"><span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={18} /></div>
            <div><span className="text-2xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[10px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={12} className="opacity-60" />}</div></div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area, ScatterChart, Scatter, ZAxis
} from 'recharts';
import { 
    Users, CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, User as UserIcon, ArrowRight, Target, Info, TrendingUp, AlertTriangle, CircleDashed, History, Zap, Timer, BarChart2, Repeat
} from 'lucide-react';

interface Props {
    user: User;
}

interface ReportDoc extends Document {
    isVirtual?: boolean;
}

const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#94a3b8',
    'En Proceso': '#3b82f6',
    'Referente': '#a855f7',
    'Control': '#f97316',
    'Terminados': '#22c55e'
};

const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6',
    'FCE': '#f87171',
    'PM': '#facc15',
    'TO BE': '#22c55e'
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const isAnalyst = user.role === UserRole.ANALYST;

    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState(isAnalyst ? user.id : '');
    const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'FLOW'>('OVERVIEW');
    const [activeType, setActiveType] = useState<string | null>(null);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];
        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = node.requiredTypes?.length ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];
                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ 
                                    ...realDoc, macroprocess: macro, process: proc, project: proj, 
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false 
                                });
                            } else {
                                unifiedList.push({ 
                                    id: `virtual-${key}`, title: `${node.name} - ${type}`, project: proj, macroprocess: macro, process: proc, microprocess: node.name, 
                                    docType: type as DocType, state: DocState.NOT_STARTED, updatedAt: new Date(0).toISOString(), assignees: node.assignees || [], isVirtual: true 
                                } as any);
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees?.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    // --- LOGICA DINAMICA DE FLUJO ---
    const dynamicMetrics = useMemo(() => {
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));
        const relevantHistory = history.filter(h => filteredDocIds.has(h.documentId));

        const docHistoryMap: Record<string, DocHistory[]> = {};
        relevantHistory.forEach(h => {
            if (!docHistoryMap[h.documentId]) docHistoryMap[h.documentId] = [];
            docHistoryMap[h.documentId].push(h);
        });

        let totalReworks = 0;
        let totalRejections = 0;
        const analystStateTimes: Record<string, Record<string, number[]>> = {}; // [analystId][state] = days[]
        const transitions: Record<string, number> = {}; // "From->To": count

        Object.keys(docHistoryMap).forEach(docId => {
            const hist = docHistoryMap[docId].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
            const docObj = filteredDocs.find(d => d.id === docId);

            for (let i = 0; i < hist.length; i++) {
                const current = hist[i];
                const next = hist[i + 1];

                // Contar rechazos
                if (current.action.toUpperCase().includes('RECHAZO') || current.action.toUpperCase().includes('RECHAZAR')) {
                    totalRejections++;
                    totalReworks++;
                }

                // Mapa de Calor y Tiempos
                if (next && docObj) {
                    const start = new Date(current.timestamp).getTime();
                    const end = new Date(next.timestamp).getTime();
                    const diffDays = Math.max(0.1, (end - start) / (1000 * 60 * 60 * 24));

                    const stateKey = current.newState;
                    docObj.assignees?.forEach(uid => {
                        if (!analystStateTimes[uid]) analystStateTimes[uid] = {};
                        if (!analystStateTimes[uid][stateKey]) analystStateTimes[uid][stateKey] = [];
                        analystStateTimes[uid][stateKey].push(diffDays);
                    });

                    // Transiciones para Sankey-like
                    const transKey = `${STATE_CONFIG[current.previousState]?.label.split('(')[0] || 'Inicio'} → ${STATE_CONFIG[current.newState]?.label.split('(')[0]}`;
                    transitions[transKey] = (transitions[transKey] || 0) + 1;
                }
            }
        });

        // Formatear para Heatmap
        const heatmapData: any[] = [];
        const statesToShow = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW, DocState.REFERENT_REVIEW, DocState.CONTROL_REVIEW];

        Object.keys(analystStateTimes).forEach(uid => {
            const user = users.find(u => u.id === uid);
            const name = user ? (user.nickname || user.name.split(' ')[0]) : 'Desc.';
            statesToShow.forEach(state => {
                const times = analystStateTimes[uid][state] || [];
                const avg = times.length > 0 ? (times.reduce((a, b) => a + b, 0) / times.length) : 0;
                if (avg > 0) {
                    heatmapData.push({ 
                        analyst: name, 
                        state: STATE_CONFIG[state].label.split('(')[0].trim(), 
                        avg: parseFloat(avg.toFixed(1)),
                        count: times.length
                    });
                }
            });
        });

        const flowSummary = Object.entries(transitions)
            .map(([name, value]) => ({ name, value }))
            .sort((a, b) => b.value - a.value)
            .slice(0, 8);

        return { totalReworks, totalRejections, heatmapData, flowSummary };
    }, [filteredDocs, history, users]);

    // --- LOGICA RESUMEN GENERAL (EXISTENTE) ---
    const overviewKPIs = useMemo(() => {
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const pending = filteredDocs.filter(d => d.state !== DocState.APPROVED && d.state !== DocState.NOT_STARTED);
        const notStarted = filteredDocs.filter(d => d.state === DocState.NOT_STARTED);
        const percent = filteredDocs.length > 0 ? Math.round((approved.length / filteredDocs.length) * 100) : 0;

        return {
            total: filteredDocs.length, totalIds: filteredDocs.map(d => d.id),
            approvedCount: approved.length, approvedIds: approved.map(d => d.id),
            pendingCount: pending.length, pendingIds: pending.map(d => d.id),
            notStartedCount: notStarted.length, notStartedIds: notStarted.map(d => d.id),
            percent
        };
    }, [filteredDocs]);

    const stateData = useMemo(() => {
        const stats = { notStarted: 0, inProcess: 0, referent: 0, control: 0, finished: 0 };
        const ids: Record<string, string[]> = { notStarted: [], inProcess: [], referent: [], control: [], finished: [] };

        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) { stats.notStarted++; ids.notStarted.push(d.id); }
            else if (d.state === DocState.APPROVED) { stats.finished++; ids.finished.push(d.id); }
            else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) { stats.referent++; ids.referent.push(d.id); }
            else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) { stats.control++; ids.control.push(d.id); }
            else { stats.inProcess++; ids.inProcess.push(d.id); }
        });
        return [
          { name: 'No Iniciado', value: stats.notStarted, ids: ids.notStarted },
          { name: 'En Proceso', value: stats.inProcess, ids: ids.inProcess },
          { name: 'Referente', value: stats.referent, ids: ids.referent },
          { name: 'Control', value: stats.control, ids: ids.control },
          { name: 'Terminados', value: stats.finished, ids: ids.finished }
        ];
    }, [filteredDocs]);

    const typeComplianceData = useMemo(() => {
        return (['AS IS', 'FCE', 'PM', 'TO BE'] as DocType[]).map(type => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const finished = docsOfType.filter(d => d.state === DocState.APPROVED);
            return { 
                type, total: docsOfType.length, finished: finished.length, 
                percent: docsOfType.length > 0 ? Math.round((finished.length / docsOfType.length) * 100) : 0, 
                color: TYPE_COLORS[type], finishedIds: finished.map(d => d.id), pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id)
            };
        });
    }, [filteredDocs]);

    const evolutionData = useMemo(() => {
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
        const now = new Date();
        const periods: any[] = [];
        for (let i = 11; i >= 0; i--) {
            const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
            periods.push({ key: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`, label: `${months[d.getMonth()]}-${String(d.getFullYear()).slice(-2)}`, 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 });
        }
        filteredDocs.filter(d => d.state === DocState.APPROVED).forEach(d => {
            const date = new Date(d.updatedAt);
            const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            const p = periods.find(x => x.key === key);
            if (p && d.docType) p[d.docType]++;
        });
        return periods;
    }, [filteredDocs]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Analizando métricas de gestión...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" /> {isAnalyst ? 'Mi Reporte Institucional' : 'Reportes de Gestión SGD'}
                    </h1>
                    <p className="text-slate-500">Métricas de cumplimiento y dinámica de flujos institucionales.</p>
                </div>
                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))).map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    {!isAnalyst && (
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    )}
                </div>
            </div>

            <div className="flex p-1 bg-slate-200/50 rounded-xl w-fit">
                <button onClick={() => setActiveTab('OVERVIEW')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'OVERVIEW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                    <BarChart2 size={16} /> Resumen General
                </button>
                <button onClick={() => setActiveTab('FLOW')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'FLOW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                    <Zap size={16} /> Dinámica de Flujo
                </button>
            </div>

            {activeTab === 'OVERVIEW' ? (
                <div className="space-y-6 animate-fadeIn">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                        <KPICard title="Total Universo" value={overviewKPIs.total} icon={FileText} color="indigo" sub="Doc. Requeridos" onClick={() => goToDashboard(overviewKPIs.totalIds)} canClick={overviewKPIs.total > 0} />
                        <KPICard title="No Iniciados" value={overviewKPIs.notStartedCount} icon={Clock} color="slate" sub="Pendiente de Carga" onClick={() => goToDashboard(overviewKPIs.notStartedIds)} canClick={overviewKPIs.notStartedCount > 0} />
                        <KPICard title="En Gestión" value={overviewKPIs.pendingCount} icon={TrendingUp} color="amber" sub="En flujo de revisión" onClick={() => goToDashboard(overviewKPIs.pendingIds)} canClick={overviewKPIs.pendingCount > 0} />
                        <KPICard title="Aprobados" value={overviewKPIs.approvedCount} icon={CheckCircle} color="green" sub={`${overviewKPIs.percent}% de la meta`} onClick={() => goToDashboard(overviewKPIs.approvedIds)} canClick={overviewKPIs.approvedCount > 0} />
                    </div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-6 flex items-center gap-2"><Target size={16} /> Cumplimiento por Tipo</h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                            {typeComplianceData.map((item) => (
                                <div key={item.type} className="flex flex-col items-center">
                                    <div className="relative w-28 h-28 mb-3">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <PieChart>
                                                <Pie data={[{ name: 'Aprobados', value: item.percent, ids: item.finishedIds, fill: item.color }, { name: 'Pendientes', value: 100 - item.percent, ids: item.pendingIds, fill: '#f1f5f9' }]} cx="50%" cy="50%" innerRadius={35} outerRadius={50} startAngle={90} endAngle={-270} dataKey="value" stroke="none" onClick={(d) => d && d.ids && d.ids.length > 0 && goToDashboard(d.ids)}>
                                                    <Cell key="progress" className="cursor-pointer" /><Cell key="bg" className="cursor-pointer" />
                                                </Pie>
                                            </PieChart>
                                        </ResponsiveContainer>
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-lg font-extrabold text-slate-800">{item.percent}%</div>
                                    </div>
                                    <span className="text-xs font-bold text-slate-700 uppercase">{item.type}</span>
                                    <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total} aprobados</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Briefcase size={16} /> Distribución por Estado</h3>
                            <div className="h-[250px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} paddingAngle={5} dataKey="value" onClick={(d) => d && d.ids && d.ids.length > 0 && goToDashboard(d.ids)}>
                                            {stateData.map((entry, index) => <Cell key={index} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} className="cursor-pointer" />)}
                                        </Pie>
                                        <Tooltip /><Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> Concentración de Carga</h3>
                             <div className="h-[250px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={stateData.filter(d => d.name !== 'No Iniciado' && d.name !== 'Terminados')}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                                        <YAxis tick={{fontSize: 10}} />
                                        <Tooltip /><Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                    </div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> Evolución Mensual (Aprobaciones)</h3>
                        <div className="h-[300px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <AreaChart data={evolutionData}>
                                    <defs>
                                        {Object.entries(TYPE_COLORS).map(([type, color]) => (
                                            <linearGradient key={type} id={`grad-${type.replace(' ', '')}`} x1="0" y1="0" x2="0" y2="1">
                                                <stop offset="5%" stopColor={color} stopOpacity={0.3}/><stop offset="95%" stopColor={color} stopOpacity={0}/>
                                            </linearGradient>
                                        ))}
                                    </defs>
                                    <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                    <XAxis dataKey="label" tick={{fontSize: 10}} />
                                    <YAxis allowDecimals={false} tick={{fontSize: 10}} />
                                    <Tooltip />
                                    <Legend onClick={(o) => setActiveType(activeType === o.dataKey ? null : o.dataKey)} />
                                    {Object.entries(TYPE_COLORS).map(([type, color]) => (
                                        <Area key={type} type="monotone" dataKey={type} stroke={color} fill={`url(#grad-${type.replace(' ', '')})`} hide={activeType !== null && activeType !== type} />
                                    ))}
                                </AreaChart>
                            </ResponsiveContainer>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="space-y-6 animate-fadeIn">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-3">
                        <KPICard title="Requeridos" value={overviewKPIs.total} icon={FileText} color="indigo" sub="Universo Total" />
                        <KPICard title="Tasa Cumplimiento" value={`${overviewKPIs.percent}%`} icon={Zap} color="green" sub="Avance a Meta" />
                        <KPICard title="Eventos Re-trabajo" value={dynamicMetrics.totalReworks} icon={Repeat} color="amber" sub="Ajustes realizados" />
                        <KPICard title="Rechazos acumulados" value={dynamicMetrics.totalRejections} icon={History} color="amber" sub="Acciones de rechazo" />
                        <KPICard title="Días Ciclo Promedio" value={dynamicMetrics.heatmapData.length > 0 ? (dynamicMetrics.heatmapData.reduce((a,b) => a+b.avg, 0) / dynamicMetrics.heatmapData.length).toFixed(1) : '-'} icon={Timer} color="slate" sub="Respuesta Global" />
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Timer size={16} /> Mapa de Calor: Tiempo de Ciclo (Analistas vs Estados)</h3>
                             <p className="text-[10px] text-slate-400 mb-6 uppercase font-bold tracking-wider">Días promedio de permanencia por etapa. Colores más intensos indican mayor duración.</p>
                             <div className="h-[400px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <ScatterChart margin={{ top: 20, right: 20, bottom: 20, left: 20 }}>
                                        <CartesianGrid strokeDasharray="3 3" />
                                        <XAxis dataKey="state" type="category" name="Estado" tick={{fontSize: 9}} />
                                        <YAxis dataKey="analyst" type="category" name="Analista" tick={{fontSize: 9}} />
                                        <ZAxis dataKey="avg" range={[50, 800]} name="Días Promedio" />
                                        <Tooltip cursor={{ strokeDasharray: '3 3' }} content={(props: any) => {
                                            if (props.active && props.payload && props.payload.length) {
                                                const data = props.payload[0].payload;
                                                return (
                                                    <div className="bg-slate-800 text-white p-3 rounded-lg shadow-xl text-xs border border-slate-700">
                                                        <p className="font-bold border-b border-slate-600 pb-1 mb-1">{data.analyst}</p>
                                                        <p><span className="opacity-70">Estado:</span> {data.state}</p>
                                                        <p><span className="opacity-70">Promedio:</span> <b className="text-indigo-400">{data.avg} días</b></p>
                                                        <p><span className="opacity-70">Eventos:</span> {data.count}</p>
                                                    </div>
                                                );
                                            }
                                            return null;
                                        }} />
                                        <Scatter name="Ciclo" data={dynamicMetrics.heatmapData}>
                                            {dynamicMetrics.heatmapData.map((entry: any, index: number) => (
                                                <Cell key={index} fill={entry.avg > 15 ? '#ef4444' : entry.avg > 7 ? '#f59e0b' : '#3b82f6'} fillOpacity={0.8} />
                                            ))}
                                        </Scatter>
                                    </ScatterChart>
                                </ResponsiveContainer>
                             </div>
                        </div>

                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Repeat size={16} /> Flujo de Transiciones</h3>
                            <div className="space-y-4">
                                {dynamicMetrics.flowSummary.length > 0 ? dynamicMetrics.flowSummary.map((t, i) => (
                                    <div key={i} className="group">
                                        <div className="flex justify-between text-xs mb-1.5">
                                            <span className="font-medium text-slate-600">{t.name}</span>
                                            <span className="font-bold text-slate-900">{t.value} docs</span>
                                        </div>
                                        <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden">
                                            <div className="bg-indigo-500 h-2 rounded-full transition-all group-hover:bg-indigo-600" style={{ width: `${(t.value / Math.max(...dynamicMetrics.flowSummary.map(x=>x.value))) * 100}%` }}></div>
                                        </div>
                                    </div>
                                )) : (
                                    <div className="flex flex-col items-center justify-center h-full py-12 text-slate-400">
                                        <History size={40} className="mb-2 opacity-20" />
                                        <p className="text-xs italic">Sin datos de transiciones aún.</p>
                                    </div>
                                )}
                            </div>
                        </div>
                    </div>

                    <div className="bg-indigo-50 border border-indigo-100 p-6 rounded-xl">
                         <div className="flex items-start gap-4">
                            <div className="p-3 bg-indigo-600 text-white rounded-lg"><Info size={24} /></div>
                            <div>
                                <h3 className="text-lg font-bold text-indigo-900 mb-1">Interpretación Dinámica</h3>
                                <p className="text-sm text-indigo-800 leading-relaxed">
                                    Esta vista analiza el <b>comportamiento histórico</b> del sistema. Un tiempo de ciclo alto en estados intermedios sugiere cuellos de botella administrativos. 
                                    Los eventos de re-trabajo detectados ({dynamicMetrics.totalReworks}) indican documentos que regresaron a analistas tras observaciones en control de gestión o referentes.
                                </p>
                            </div>
                         </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { 
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', 
        green: 'bg-green-50 text-green-600 border-green-100',
        amber: 'bg-amber-50 text-amber-600 border-amber-100',
        slate: 'bg-slate-50 text-slate-600 border-slate-100'
    };
    return (
        <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md transition-all active:scale-95' : ''}`}>
            <div className="flex justify-between items-start mb-2"><span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={18} /></div>
            <div><span className="text-2xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[10px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={12} className="opacity-60" />}</div></div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area, ScatterChart, Scatter, ZAxis
} from 'recharts';
import { 
    CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, ArrowRight, Target, Info, TrendingUp, AlertTriangle, History, Zap, Timer, BarChart2, Repeat
} from 'lucide-react';

interface Props {
    user: User;
}

interface ReportDoc extends Document {
    isVirtual?: boolean;
}

const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#94a3b8',
    'En Proceso': '#3b82f6',
    'Referente': '#a855f7',
    'Control': '#f97316',
    'Terminados': '#22c55e'
};

const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6',
    'FCE': '#f87171',
    'PM': '#facc15',
    'TO BE': '#22c55e'
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const isAnalyst = user.role === UserRole.ANALYST;

    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState(isAnalyst ? user.id : '');
    const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'FLOW'>('OVERVIEW');
    const [activeType, setActiveType] = useState<string | null>(null);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];
        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = node.requiredTypes?.length ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];
                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ 
                                    ...realDoc, macroprocess: macro, process: proc, project: proj, 
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false 
                                });
                            } else {
                                unifiedList.push({ 
                                    id: `virtual-${key}`, title: `${node.name} - ${type}`, project: proj, macroprocess: macro, process: proc, microprocess: node.name, 
                                    docType: type as DocType, state: DocState.NOT_STARTED, updatedAt: new Date(0).toISOString(), assignees: node.assignees || [], isVirtual: true 
                                } as any);
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees?.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    // --- KPIs GENERALES (MANTENIDOS SEGÚN ORIGINAL) ---
    const overviewKPIs = useMemo(() => {
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const pending = filteredDocs.filter(d => d.state !== DocState.APPROVED && d.state !== DocState.NOT_STARTED);
        const notStarted = filteredDocs.filter(d => d.state === DocState.NOT_STARTED);
        const percent = filteredDocs.length > 0 ? Math.round((approved.length / filteredDocs.length) * 100) : 0;

        return {
            total: filteredDocs.length, totalIds: filteredDocs.map(d => d.id),
            approvedCount: approved.length, approvedIds: approved.map(d => d.id),
            pendingCount: pending.length, pendingIds: pending.map(d => d.id),
            notStartedCount: notStarted.length, notStartedIds: notStarted.map(d => d.id),
            percent
        };
    }, [filteredDocs]);

    const stateData = useMemo(() => {
        const stats = { notStarted: 0, inProcess: 0, referent: 0, control: 0, finished: 0 };
        const ids: Record<string, string[]> = { notStarted: [], inProcess: [], referent: [], control: [], finished: [] };

        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) { stats.notStarted++; ids.notStarted.push(d.id); }
            else if (d.state === DocState.APPROVED) { stats.finished++; ids.finished.push(d.id); }
            else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) { stats.referent++; ids.referent.push(d.id); }
            else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) { stats.control++; ids.control.push(d.id); }
            else { stats.inProcess++; ids.inProcess.push(d.id); }
        });
        return [
          { name: 'No Iniciado', value: stats.notStarted, ids: ids.notStarted },
          { name: 'En Proceso', value: stats.inProcess, ids: ids.inProcess },
          { name: 'Referente', value: stats.referent, ids: ids.referent },
          { name: 'Control', value: stats.control, ids: ids.control },
          { name: 'Terminados', value: stats.finished, ids: ids.finished }
        ];
    }, [filteredDocs]);

    const analystProductivityData = useMemo(() => {
        const analystMap: Record<string, { name: string, total: number, finished: number }> = {};
        filteredDocs.forEach(doc => {
            doc.assignees?.forEach(uid => {
                const user = users.find(u => u.id === uid);
                if (user && user.role === UserRole.ANALYST) {
                    if (!analystMap[uid]) analystMap[uid] = { name: user.nickname || user.name.split(' ')[0], total: 0, finished: 0 };
                    analystMap[uid].total++;
                    if (doc.state === DocState.APPROVED) analystMap[uid].finished++;
                }
            });
        });
        return Object.values(analystMap).sort((a, b) => b.total - a.total);
    }, [filteredDocs, users]);

    const typeComplianceData = useMemo(() => {
        return (['AS IS', 'FCE', 'PM', 'TO BE'] as DocType[]).map(type => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const finished = docsOfType.filter(d => d.state === DocState.APPROVED);
            return { 
                type, total: docsOfType.length, finished: finished.length, 
                percent: docsOfType.length > 0 ? Math.round((finished.length / docsOfType.length) * 100) : 0, 
                color: TYPE_COLORS[type], finishedIds: finished.map(d => d.id), pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id)
            };
        });
    }, [filteredDocs]);

    const evolutionData = useMemo(() => {
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
        const now = new Date();
        const periods: any[] = [];
        for (let i = 11; i >= 0; i--) {
            const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
            periods.push({ key: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`, label: `${months[d.getMonth()]}-${String(d.getFullYear()).slice(-2)}`, 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 });
        }
        filteredDocs.filter(d => d.state === DocState.APPROVED).forEach(d => {
            const date = new Date(d.updatedAt);
            const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            const p = periods.find(x => x.key === key);
            if (p && d.docType) p[d.docType]++;
        });
        return periods;
    }, [filteredDocs]);

    // --- DINÁMICA DE FLUJO (MODULO NUEVO) ---
    const dynamicMetrics = useMemo(() => {
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));
        const relevantHistory = history.filter(h => filteredDocIds.has(h.documentId));
        const docHistoryMap: Record<string, DocHistory[]> = {};
        relevantHistory.forEach(h => { if (!docHistoryMap[h.documentId]) docHistoryMap[h.documentId] = []; docHistoryMap[h.documentId].push(h); });

        let totalReworks = 0; let totalRejections = 0;
        const analystStateTimes: Record<string, Record<string, number[]>> = {};
        const transitions: Record<string, number> = {};

        Object.keys(docHistoryMap).forEach(docId => {
            const hist = docHistoryMap[docId].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
            const docObj = filteredDocs.find(d => d.id === docId);
            for (let i = 0; i < hist.length; i++) {
                const current = hist[i]; const next = hist[i + 1];
                if (current.action.toUpperCase().includes('RECHAZO') || current.action.toUpperCase().includes('RECHAZAR')) { totalRejections++; totalReworks++; }
                if (next && docObj) {
                    const diffDays = Math.max(0.1, (new Date(next.timestamp).getTime() - new Date(current.timestamp).getTime()) / (1000 * 60 * 60 * 24));
                    docObj.assignees?.forEach(uid => {
                        if (!analystStateTimes[uid]) analystStateTimes[uid] = {};
                        if (!analystStateTimes[uid][current.newState]) analystStateTimes[uid][current.newState] = [];
                        analystStateTimes[uid][current.newState].push(diffDays);
                    });
                    const transKey = `${STATE_CONFIG[current.previousState]?.label.split('(')[0] || 'Inicio'} → ${STATE_CONFIG[current.newState]?.label.split('(')[0]}`;
                    transitions[transKey] = (transitions[transKey] || 0) + 1;
                }
            }
        });

        const heatmapData: any[] = [];
        const statesToShow = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW, DocState.REFERENT_REVIEW, DocState.CONTROL_REVIEW];
        Object.keys(analystStateTimes).forEach(uid => {
            const user = users.find(u => u.id === uid);
            statesToShow.forEach(state => {
                const times = analystStateTimes[uid][state] || [];
                const avg = times.length > 0 ? (times.reduce((a, b) => a + b, 0) / times.length) : 0;
                if (avg > 0) heatmapData.push({ analyst: user ? (user.nickname || user.name.split(' ')[0]) : 'Des.', state: STATE_CONFIG[state].label.split('(')[0].trim(), avg: parseFloat(avg.toFixed(1)), count: times.length });
            });
        });

        return { totalReworks, totalRejections, heatmapData, flowSummary: Object.entries(transitions).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8) };
    }, [filteredDocs, history, users]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Procesando Reportes Institucionales...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" /> Reportes de Gestión SGD
                    </h1>
                    <p className="text-slate-500">Métricas de cumplimiento y cierre de procesos.</p>
                </div>
                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))).map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    {!isAnalyst && (
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    )}
                </div>
            </div>

            <div className="flex p-1 bg-slate-200/50 rounded-xl w-fit">
                <button onClick={() => setActiveTab('OVERVIEW')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'OVERVIEW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                    <BarChart2 size={16} /> Resumen General
                </button>
                <button onClick={() => setActiveTab('FLOW')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'FLOW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                    <Zap size={16} /> Dinámica de Flujo
                </button>
            </div>

            {activeTab === 'OVERVIEW' ? (
                <div className="space-y-6 animate-fadeIn">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                        <KPICard title="TOTAL UNIVERSO" value={overviewKPIs.total} icon={FileText} color="indigo" sub="Doc. Requeridos" onClick={() => goToDashboard(overviewKPIs.totalIds)} canClick={overviewKPIs.total > 0} />
                        <KPICard title="NO INICIADOS" value={overviewKPIs.notStartedCount} icon={Clock} color="slate" sub="Pendiente de Carga" onClick={() => goToDashboard(overviewKPIs.notStartedIds)} canClick={overviewKPIs.notStartedCount > 0} />
                        <KPICard title="EN GESTIÓN" value={overviewKPIs.pendingCount} icon={TrendingUp} color="amber" sub="En flujo de revisión" onClick={() => goToDashboard(overviewKPIs.pendingIds)} canClick={overviewKPIs.pendingCount > 0} />
                        <KPICard title="APROBADOS" value={overviewKPIs.approvedCount} icon={CheckCircle} color="green" sub={`${overviewKPIs.percent}% de la meta`} onClick={() => goToDashboard(overviewKPIs.approvedIds)} canClick={overviewKPIs.approvedCount > 0} />
                    </div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-6 flex items-center gap-2"><Target size={16} /> CUMPLIMIENTO POR TIPO</h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                            {typeComplianceData.map((item) => (
                                <div key={item.type} className="flex flex-col items-center">
                                    <div className="relative w-28 h-28 mb-3">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <PieChart>
                                                <Pie data={[{ name: 'Aprobados', value: item.percent, ids: item.finishedIds, fill: item.color }, { name: 'Pendientes', value: 100 - item.percent, ids: item.pendingIds, fill: '#f1f5f9' }]} cx="50%" cy="50%" innerRadius={35} outerRadius={50} startAngle={90} endAngle={-270} dataKey="value" stroke="none" onClick={(d) => d && d.ids && d.ids.length > 0 && goToDashboard(d.ids)}>
                                                    <Cell key="progress" className="cursor-pointer" /><Cell key="bg" className="cursor-pointer" />
                                                </Pie>
                                            </PieChart>
                                        </ResponsiveContainer>
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-lg font-extrabold text-slate-800">{item.percent}%</div>
                                    </div>
                                    <span className="text-xs font-bold text-slate-700 uppercase">{item.type}</span>
                                    <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total} aprobados</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Briefcase size={16} /> DISTRIBUCIÓN POR ESTADO</h3>
                            <div className="h-[250px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} paddingAngle={5} dataKey="value" onClick={(d) => d && d.ids && d.ids.length > 0 && goToDashboard(d.ids)}>
                                            {stateData.map((entry, index) => <Cell key={index} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} className="cursor-pointer" />)}
                                        </Pie>
                                        <Tooltip /><Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> CONCENTRACIÓN DE CARGA</h3>
                             <div className="h-[250px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={stateData.filter(d => d.name !== 'No Iniciado' && d.name !== 'Terminados')}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                                        <YAxis tick={{fontSize: 10}} />
                                        <Tooltip /><Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Users size={16} /> FLUJO DE PRODUCTIVIDAD POR ANALISTA</h3>
                            <div className="h-[300px]">
                                {analystProductivityData.length > 0 ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <BarChart data={analystProductivityData} layout="vertical" margin={{ left: 20 }}>
                                            <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                                            <XAxis type="number" tick={{fontSize: 10}} />
                                            <YAxis dataKey="name" type="category" tick={{fontSize: 10}} width={80} />
                                            <Tooltip />
                                            <Legend />
                                            <Bar dataKey="finished" name="Terminados" stackId="a" fill="#22c55e" radius={[0, 0, 0, 0]} />
                                            <Bar dataKey="total" name="En Proceso" stackId="a" fill="#6366f1" radius={[0, 4, 4, 0]} />
                                        </BarChart>
                                    </ResponsiveContainer>
                                ) : <div className="h-full flex items-center justify-center text-slate-400 italic text-sm">Sin datos de analistas.</div>}
                            </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> EVOLUCIÓN MENSUAL</h3>
                            <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <AreaChart data={evolutionData}>
                                        <defs>
                                            {Object.entries(TYPE_COLORS).map(([type, color]) => (
                                                <linearGradient key={type} id={`grad-${type.replace(' ', '')}`} x1="0" y1="0" x2="0" y2="1">
                                                    <stop offset="5%" stopColor={color} stopOpacity={0.3}/><stop offset="95%" stopColor={color} stopOpacity={0}/>
                                                </linearGradient>
                                            ))}
                                        </defs>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="label" tick={{fontSize: 10}} />
                                        <YAxis allowDecimals={false} tick={{fontSize: 10}} label={{ value: 'Aprobaciones', angle: -90, position: 'insideLeft', fontSize: 10 }} />
                                        <Tooltip />
                                        <Legend onClick={(o) => setActiveType(activeType === o.dataKey ? null : o.dataKey)} />
                                        {Object.entries(TYPE_COLORS).map(([type, color]) => (
                                            <Area key={type} type="monotone" dataKey={type} stroke={color} fill={`url(#grad-${type.replace(' ', '')})`} hide={activeType !== null && activeType !== type} />
                                        ))}
                                    </AreaChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="space-y-6 animate-fadeIn">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-3">
                        <KPICard title="Requeridos" value={overviewKPIs.total} icon={FileText} color="indigo" sub="Universo Total" />
                        <KPICard title="Tasa Cumplimiento" value={`${overviewKPIs.percent}%`} icon={Zap} color="green" sub="Avance a Meta" />
                        <KPICard title="Eventos Re-trabajo" value={dynamicMetrics.totalReworks} icon={Repeat} color="amber" sub="Ajustes realizados" />
                        <KPICard title="Rechazos acumulados" value={dynamicMetrics.totalRejections} icon={History} color="amber" sub="Acciones de rechazo" />
                        <KPICard title="Días Ciclo Promedio" value={dynamicMetrics.heatmapData.length > 0 ? (dynamicMetrics.heatmapData.reduce((a,b) => a+b.avg, 0) / dynamicMetrics.heatmapData.length).toFixed(1) : '-'} icon={Timer} color="slate" sub="Respuesta Global" />
                    </div>
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Timer size={16} /> Mapa de Calor: Tiempo de Ciclo</h3>
                             <p className="text-[10px] text-slate-400 mb-6 uppercase font-bold tracking-wider">Días promedio de permanencia. Colores intensos indican cuellos de botella.</p>
                             <div className="h-[400px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <ScatterChart margin={{ top: 20, right: 20, bottom: 20, left: 20 }}>
                                        <CartesianGrid strokeDasharray="3 3" />
                                        <XAxis dataKey="state" type="category" name="Estado" tick={{fontSize: 9}} />
                                        <YAxis dataKey="analyst" type="category" name="Analista" tick={{fontSize: 9}} />
                                        <ZAxis dataKey="avg" range={[50, 800]} name="Días Promedio" />
                                        <Tooltip cursor={{ strokeDasharray: '3 3' }} content={(props: any) => {
                                            if (props.active && props.payload && props.payload.length) {
                                                const data = props.payload[0].payload;
                                                return (
                                                    <div className="bg-slate-800 text-white p-3 rounded-lg shadow-xl text-xs border border-slate-700">
                                                        <p className="font-bold border-b border-slate-600 pb-1 mb-1">{data.analyst}</p>
                                                        <p><span className="opacity-70">Estado:</span> {data.state}</p>
                                                        <p><span className="opacity-70">Promedio:</span> <b className="text-indigo-400">{data.avg} días</b></p>
                                                        <p><span className="opacity-70">Eventos:</span> {data.count}</p>
                                                    </div>
                                                );
                                            }
                                            return null;
                                        }} />
                                        <Scatter name="Ciclo" data={dynamicMetrics.heatmapData}>
                                            {dynamicMetrics.heatmapData.map((entry: any, index: number) => (
                                                <Cell key={index} fill={entry.avg > 15 ? '#ef4444' : entry.avg > 7 ? '#f59e0b' : '#3b82f6'} fillOpacity={0.8} />
                                            ))}
                                        </Scatter>
                                    </ScatterChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Repeat size={16} /> Flujo de Transiciones</h3>
                            <div className="space-y-4">
                                {dynamicMetrics.flowSummary.length > 0 ? dynamicMetrics.flowSummary.map((t, i) => (
                                    <div key={i} className="group">
                                        <div className="flex justify-between text-xs mb-1.5">
                                            <span className="font-medium text-slate-600">{t.name}</span>
                                            <span className="font-bold text-slate-900">{t.value} docs</span>
                                        </div>
                                        <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden">
                                            <div className="bg-indigo-500 h-2 rounded-full transition-all group-hover:bg-indigo-600" style={{ width: `${(t.value / Math.max(...dynamicMetrics.flowSummary.map(x=>x.value))) * 100}%` }}></div>
                                        </div>
                                    </div>
                                )) : <div className="flex flex-col items-center justify-center py-12 text-slate-400 italic text-xs">Sin datos aún.</div>}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { 
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', 
        green: 'bg-green-50 text-green-600 border-green-100',
        amber: 'bg-amber-50 text-amber-600 border-amber-100',
        slate: 'bg-slate-50 text-slate-600 border-slate-100'
    };
    return (
        <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md transition-all active:scale-95' : ''}`}>
            <div className="flex justify-between items-start mb-2"><span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={18} /></div>
            <div><span className="text-2xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[10px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={12} className="opacity-60" />}</div></div>
        </div>
    );
};

export default Reports;

import React, { useEffect, useState, useMemo } from 'react';
import { useNavigate } from 'react-router-dom';
import { DocumentService, UserService, HierarchyService, HistoryService, normalizeHeader } from '../services/firebaseBackend';
import { Document, User, DocState, FullHierarchy, DocType, UserRole, DocHistory } from '../types';
import { STATE_CONFIG } from '../constants';
import { 
    PieChart, Pie, Cell, BarChart, Bar, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer, AreaChart, Area, ScatterChart, Scatter, ZAxis
} from 'recharts';
import { 
    CheckCircle, Clock, FileText, Filter, LayoutDashboard, Briefcase, Loader2, ArrowRight, Target, Info, TrendingUp, AlertTriangle, History, Zap, Timer, BarChart2, Repeat, Users
} from 'lucide-react';

interface Props {
    user: User;
}

interface ReportDoc extends Document {
    isVirtual?: boolean;
}

const STATE_COLOR_MAP: Record<string, string> = {
    'No Iniciado': '#94a3b8',
    'En Proceso': '#3b82f6',
    'Referente': '#a855f7',
    'Control': '#f97316',
    'Terminados': '#22c55e'
};

const TYPE_COLORS: Record<string, string> = {
    'AS IS': '#3b82f6',
    'FCE': '#f87171',
    'PM': '#facc15',
    'TO BE': '#22c55e'
};

const Reports: React.FC<Props> = ({ user }) => {
    const navigate = useNavigate();
    const isAnalyst = user.role === UserRole.ANALYST;

    const [realDocs, setRealDocs] = useState<Document[]>([]);
    const [history, setHistory] = useState<DocHistory[]>([]);
    const [hierarchy, setHierarchy] = useState<FullHierarchy>({});
    const [users, setUsers] = useState<User[]>([]);
    const [loading, setLoading] = useState(true);

    const [filterProject, setFilterProject] = useState('');
    const [filterAnalyst, setFilterAnalyst] = useState(isAnalyst ? user.id : '');
    const [activeTab, setActiveTab] = useState<'OVERVIEW' | 'FLOW'>('OVERVIEW');
    const [activeType, setActiveType] = useState<string | null>(null);

    useEffect(() => {
        loadData();
    }, []);

    const loadData = async () => {
        setLoading(true);
        try {
            const [d, u, h, hist] = await Promise.all([
                DocumentService.getAll(),
                UserService.getAll(),
                HierarchyService.getFullHierarchy(),
                HistoryService.getAll()
            ]);
            setRealDocs(d);
            setUsers(u);
            setHierarchy(h);
            setHistory(hist);
        } catch (error) {
            console.error(error);
        } finally {
            setLoading(false);
        }
    };

    const unifiedData = useMemo(() => {
        if (Object.keys(hierarchy).length === 0) return [];
        const unifiedList: ReportDoc[] = [];
        const realDocMap = new Map<string, Document>();

        realDocs.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalizeHeader(doc.project)}|${normalizeHeader(microName)}|${normalizeHeader(docType)}`;
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        Object.keys(hierarchy).forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    hierarchy[proj][macro][proc].forEach(node => {
                        if (node.active === false) return;
                        const requiredTypes = node.requiredTypes?.length ? node.requiredTypes : ['AS IS', 'FCE', 'PM', 'TO BE'];
                        requiredTypes.forEach(type => {
                            const key = `${normalizeHeader(proj)}|${normalizeHeader(node.name)}|${normalizeHeader(type)}`;
                            if (realDocMap.has(key)) {
                                const realDoc = realDocMap.get(key)!;
                                unifiedList.push({ 
                                    ...realDoc, macroprocess: macro, process: proc, project: proj, 
                                    assignees: (node.assignees && node.assignees.length > 0) ? node.assignees : (realDoc.assignees || []),
                                    isVirtual: false 
                                });
                            } else {
                                unifiedList.push({ 
                                    id: `virtual-${key}`, title: `${node.name} - ${type}`, project: proj, macroprocess: macro, process: proc, microprocess: node.name, 
                                    docType: type as DocType, state: DocState.NOT_STARTED, updatedAt: new Date(0).toISOString(), assignees: node.assignees || [], isVirtual: true 
                                } as any);
                            }
                        });
                    });
                });
            });
        });
        return unifiedList;
    }, [realDocs, hierarchy]);

    const filteredDocs = useMemo(() => {
        let docs = unifiedData;
        if (filterProject) docs = docs.filter(d => d.project === filterProject);
        if (filterAnalyst) docs = docs.filter(d => d.assignees?.includes(filterAnalyst));
        return docs;
    }, [unifiedData, filterProject, filterAnalyst]);

    // --- KPIs GENERALES (MANTENIDOS SEGÚN ORIGINAL) ---
    const overviewKPIs = useMemo(() => {
        const approved = filteredDocs.filter(d => d.state === DocState.APPROVED);
        const pending = filteredDocs.filter(d => d.state !== DocState.APPROVED && d.state !== DocState.NOT_STARTED);
        const notStarted = filteredDocs.filter(d => d.state === DocState.NOT_STARTED);
        const percent = filteredDocs.length > 0 ? Math.round((approved.length / filteredDocs.length) * 100) : 0;

        return {
            total: filteredDocs.length, totalIds: filteredDocs.map(d => d.id),
            approvedCount: approved.length, approvedIds: approved.map(d => d.id),
            pendingCount: pending.length, pendingIds: pending.map(d => d.id),
            notStartedCount: notStarted.length, notStartedIds: notStarted.map(d => d.id),
            percent
        };
    }, [filteredDocs]);

    const stateData = useMemo(() => {
        const stats = { notStarted: 0, inProcess: 0, referent: 0, control: 0, finished: 0 };
        const ids: Record<string, string[]> = { notStarted: [], inProcess: [], referent: [], control: [], finished: [] };

        filteredDocs.forEach(d => {
            if (d.state === DocState.NOT_STARTED) { stats.notStarted++; ids.notStarted.push(d.id); }
            else if (d.state === DocState.APPROVED) { stats.finished++; ids.finished.push(d.id); }
            else if (d.state === DocState.SENT_TO_REFERENT || d.state === DocState.REFERENT_REVIEW) { stats.referent++; ids.referent.push(d.id); }
            else if (d.state === DocState.SENT_TO_CONTROL || d.state === DocState.CONTROL_REVIEW) { stats.control++; ids.control.push(d.id); }
            else { stats.inProcess++; ids.inProcess.push(d.id); }
        });
        return [
          { name: 'No Iniciado', value: stats.notStarted, ids: ids.notStarted },
          { name: 'En Proceso', value: stats.inProcess, ids: ids.inProcess },
          { name: 'Referente', value: stats.referent, ids: ids.referent },
          { name: 'Control', value: stats.control, ids: ids.control },
          { name: 'Terminados', value: stats.finished, ids: ids.finished }
        ];
    }, [filteredDocs]);

    const analystProductivityData = useMemo(() => {
        const analystMap: Record<string, { name: string, total: number, finished: number }> = {};
        filteredDocs.forEach(doc => {
            doc.assignees?.forEach(uid => {
                const user = users.find(u => u.id === uid);
                if (user && user.role === UserRole.ANALYST) {
                    if (!analystMap[uid]) analystMap[uid] = { name: user.nickname || user.name.split(' ')[0], total: 0, finished: 0 };
                    analystMap[uid].total++;
                    if (doc.state === DocState.APPROVED) analystMap[uid].finished++;
                }
            });
        });
        return Object.values(analystMap).sort((a, b) => b.total - a.total);
    }, [filteredDocs, users]);

    const typeComplianceData = useMemo(() => {
        return (['AS IS', 'FCE', 'PM', 'TO BE'] as DocType[]).map(type => {
            const docsOfType = filteredDocs.filter(d => d.docType === type);
            const finished = docsOfType.filter(d => d.state === DocState.APPROVED);
            return { 
                type, total: docsOfType.length, finished: finished.length, 
                percent: docsOfType.length > 0 ? Math.round((finished.length / docsOfType.length) * 100) : 0, 
                color: TYPE_COLORS[type], finishedIds: finished.map(d => d.id), pendingIds: docsOfType.filter(d => d.state !== DocState.APPROVED).map(d => d.id)
            };
        });
    }, [filteredDocs]);

    const evolutionData = useMemo(() => {
        const months = ['Ene', 'Feb', 'Mar', 'Abr', 'May', 'Jun', 'Jul', 'Ago', 'Sep', 'Oct', 'Nov', 'Dic'];
        const now = new Date();
        const periods: any[] = [];
        for (let i = 11; i >= 0; i--) {
            const d = new Date(now.getFullYear(), now.getMonth() - i, 1);
            periods.push({ key: `${d.getFullYear()}-${String(d.getMonth() + 1).padStart(2, '0')}`, label: `${months[d.getMonth()]}-${String(d.getFullYear()).slice(-2)}`, 'AS IS': 0, 'FCE': 0, 'PM': 0, 'TO BE': 0 });
        }
        filteredDocs.filter(d => d.state === DocState.APPROVED).forEach(d => {
            const date = new Date(d.updatedAt);
            const key = `${date.getFullYear()}-${String(date.getMonth() + 1).padStart(2, '0')}`;
            const p = periods.find(x => x.key === key);
            if (p && d.docType) p[d.docType]++;
        });
        return periods;
    }, [filteredDocs]);

    // --- DINÁMICA DE FLUJO (MODULO NUEVO) ---
    const dynamicMetrics = useMemo(() => {
        const filteredDocIds = new Set(filteredDocs.map(d => d.id));
        const relevantHistory = history.filter(h => filteredDocIds.has(h.documentId));
        const docHistoryMap: Record<string, DocHistory[]> = {};
        relevantHistory.forEach(h => { if (!docHistoryMap[h.documentId]) docHistoryMap[h.documentId] = []; docHistoryMap[h.documentId].push(h); });

        let totalReworks = 0; let totalRejections = 0;
        const analystStateTimes: Record<string, Record<string, number[]>> = {};
        const transitions: Record<string, number> = {};

        Object.keys(docHistoryMap).forEach(docId => {
            const hist = docHistoryMap[docId].sort((a, b) => new Date(a.timestamp).getTime() - new Date(b.timestamp).getTime());
            const docObj = filteredDocs.find(d => d.id === docId);
            for (let i = 0; i < hist.length; i++) {
                const current = hist[i]; const next = hist[i + 1];
                if (current.action.toUpperCase().includes('RECHAZO') || current.action.toUpperCase().includes('RECHAZAR')) { totalRejections++; totalReworks++; }
                if (next && docObj) {
                    const diffDays = Math.max(0.1, (new Date(next.timestamp).getTime() - new Date(current.timestamp).getTime()) / (1000 * 60 * 60 * 24));
                    docObj.assignees?.forEach(uid => {
                        if (!analystStateTimes[uid]) analystStateTimes[uid] = {};
                        if (!analystStateTimes[uid][current.newState]) analystStateTimes[uid][current.newState] = [];
                        analystStateTimes[uid][current.newState].push(diffDays);
                    });
                    const transKey = `${STATE_CONFIG[current.previousState]?.label.split('(')[0] || 'Inicio'} → ${STATE_CONFIG[current.newState]?.label.split('(')[0]}`;
                    transitions[transKey] = (transitions[transKey] || 0) + 1;
                }
            }
        });

        const heatmapData: any[] = [];
        const statesToShow = [DocState.INITIATED, DocState.IN_PROCESS, DocState.INTERNAL_REVIEW, DocState.REFERENT_REVIEW, DocState.CONTROL_REVIEW];
        Object.keys(analystStateTimes).forEach(uid => {
            const user = users.find(u => u.id === uid);
            statesToShow.forEach(state => {
                const times = analystStateTimes[uid][state] || [];
                const avg = times.length > 0 ? (times.reduce((a, b) => a + b, 0) / times.length) : 0;
                if (avg > 0) heatmapData.push({ analyst: user ? (user.nickname || user.name.split(' ')[0]) : 'Des.', state: STATE_CONFIG[state].label.split('(')[0].trim(), avg: parseFloat(avg.toFixed(1)), count: times.length });
            });
        });

        return { totalReworks, totalRejections, heatmapData, flowSummary: Object.entries(transitions).map(([name, value]) => ({ name, value })).sort((a, b) => b.value - a.value).slice(0, 8) };
    }, [filteredDocs, history, users]);

    const goToDashboard = (ids: string[]) => navigate('/', { state: { filterIds: ids, fromReport: true } });

    if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Loader2 className="animate-spin mb-2" /> Procesando Reportes Institucionales...</div>;

    return (
        <div className="space-y-6 pb-12">
            <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
                <div>
                    <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                        <LayoutDashboard className="text-indigo-600" /> Reportes de Gestión SGD
                    </h1>
                    <p className="text-slate-500">Métricas de cumplimiento y cierre de procesos.</p>
                </div>
                <div className="flex flex-wrap items-center gap-2 bg-white p-1.5 rounded-lg border border-slate-200 shadow-sm">
                    <Filter size={16} className="text-slate-400 ml-2" />
                    <select value={filterProject} onChange={(e) => setFilterProject(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px] border-r border-slate-100">
                        <option value="">Todos los Proyectos</option>
                        {Array.from(new Set(unifiedData.map(d => d.project).filter(Boolean))).map(p => <option key={p} value={p}>{p}</option>)}
                    </select>
                    {!isAnalyst && (
                        <select value={filterAnalyst} onChange={(e) => setFilterAnalyst(e.target.value)} className="bg-transparent text-sm font-medium text-slate-700 outline-none p-1 min-w-[150px]">
                            <option value="">Todos los Analistas</option>
                            {users.filter(u => u.role === UserRole.ANALYST).map(u => <option key={u.id} value={u.id}>{u.name}</option>)}
                        </select>
                    )}
                </div>
            </div>

            <div className="flex p-1 bg-slate-200/50 rounded-xl w-fit">
                <button onClick={() => setActiveTab('OVERVIEW')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'OVERVIEW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                    <BarChart2 size={16} /> Resumen General
                </button>
                <button onClick={() => setActiveTab('FLOW')} className={`flex items-center gap-2 px-6 py-2 rounded-lg text-sm font-bold transition-all ${activeTab === 'FLOW' ? 'bg-white text-indigo-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>
                    <Zap size={16} /> Dinámica de Flujo
                </button>
            </div>

            {activeTab === 'OVERVIEW' ? (
                <div className="space-y-6 animate-fadeIn">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-3">
                        <KPICard title="TOTAL UNIVERSO" value={overviewKPIs.total} icon={FileText} color="indigo" sub="Doc. Requeridos" onClick={() => goToDashboard(overviewKPIs.totalIds)} canClick={overviewKPIs.total > 0} />
                        <KPICard title="NO INICIADOS" value={overviewKPIs.notStartedCount} icon={Clock} color="slate" sub="Pendiente de Carga" onClick={() => goToDashboard(overviewKPIs.notStartedIds)} canClick={overviewKPIs.notStartedCount > 0} />
                        <KPICard title="EN GESTIÓN" value={overviewKPIs.pendingCount} icon={TrendingUp} color="amber" sub="En flujo de revisión" onClick={() => goToDashboard(overviewKPIs.pendingIds)} canClick={overviewKPIs.pendingCount > 0} />
                        <KPICard title="APROBADOS" value={overviewKPIs.approvedCount} icon={CheckCircle} color="green" sub={`${overviewKPIs.percent}% de la meta`} onClick={() => goToDashboard(overviewKPIs.approvedIds)} canClick={overviewKPIs.approvedCount > 0} />
                    </div>

                    <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                        <h3 className="text-sm font-bold text-slate-700 uppercase mb-6 flex items-center gap-2"><Target size={16} /> CUMPLIMIENTO POR TIPO</h3>
                        <div className="grid grid-cols-2 md:grid-cols-4 gap-6">
                            {typeComplianceData.map((item) => (
                                <div key={item.type} className="flex flex-col items-center">
                                    <div className="relative w-28 h-28 mb-3">
                                        <ResponsiveContainer width="100%" height="100%">
                                            <PieChart>
                                                <Pie data={[{ name: 'Aprobados', value: item.percent, ids: item.finishedIds, fill: item.color }, { name: 'Pendientes', value: 100 - item.percent, ids: item.pendingIds, fill: '#f1f5f9' }]} cx="50%" cy="50%" innerRadius={35} outerRadius={50} startAngle={90} endAngle={-270} dataKey="value" stroke="none" onClick={(d) => d && d.ids && d.ids.length > 0 && goToDashboard(d.ids)}>
                                                    <Cell key="progress" className="cursor-pointer" /><Cell key="bg" className="cursor-pointer" />
                                                </Pie>
                                            </PieChart>
                                        </ResponsiveContainer>
                                        <div className="absolute inset-0 flex items-center justify-center pointer-events-none text-lg font-extrabold text-slate-800">{item.percent}%</div>
                                    </div>
                                    <span className="text-xs font-bold text-slate-700 uppercase">{item.type}</span>
                                    <span className="text-[10px] text-slate-400 mt-1">{item.finished} de {item.total} aprobados</span>
                                </div>
                            ))}
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Briefcase size={16} /> DISTRIBUCIÓN POR ESTADO</h3>
                            <div className="h-[250px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <PieChart>
                                        <Pie data={stateData} cx="50%" cy="50%" innerRadius={60} outerRadius={85} paddingAngle={5} dataKey="value" onClick={(d) => d && d.ids && d.ids.length > 0 && goToDashboard(d.ids)}>
                                            {stateData.map((entry, index) => <Cell key={index} fill={STATE_COLOR_MAP[entry.name] || '#94a3b8'} className="cursor-pointer" />)}
                                        </Pie>
                                        <Tooltip /><Legend />
                                    </PieChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> CONCENTRACIÓN DE CARGA</h3>
                             <div className="h-[250px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <BarChart data={stateData.filter(d => d.name !== 'No Iniciado' && d.name !== 'Terminados')}>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="name" tick={{fontSize: 10}} />
                                        <YAxis tick={{fontSize: 10}} />
                                        <Tooltip /><Bar dataKey="value" fill="#6366f1" radius={[4, 4, 0, 0]} />
                                    </BarChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                    </div>

                    <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Users size={16} /> FLUJO DE PRODUCTIVIDAD POR ANALISTA</h3>
                            <div className="h-[300px]">
                                {analystProductivityData.length > 0 ? (
                                    <ResponsiveContainer width="100%" height="100%">
                                        <BarChart data={analystProductivityData} layout="vertical" margin={{ left: 20 }}>
                                            <CartesianGrid strokeDasharray="3 3" horizontal={false} stroke="#f1f5f9" />
                                            <XAxis type="number" tick={{fontSize: 10}} />
                                            <YAxis dataKey="name" type="category" tick={{fontSize: 10}} width={80} />
                                            <Tooltip />
                                            <Legend />
                                            <Bar dataKey="finished" name="Terminados" stackId="a" fill="#22c55e" radius={[0, 0, 0, 0]} />
                                            <Bar dataKey="total" name="En Proceso" stackId="a" fill="#6366f1" radius={[0, 4, 4, 0]} />
                                        </BarChart>
                                    </ResponsiveContainer>
                                ) : <div className="h-full flex items-center justify-center text-slate-400 italic text-sm">Sin datos de analistas.</div>}
                            </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><TrendingUp size={16} /> EVOLUCIÓN MENSUAL</h3>
                            <div className="h-[300px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <AreaChart data={evolutionData}>
                                        <defs>
                                            {Object.entries(TYPE_COLORS).map(([type, color]) => (
                                                <linearGradient key={type} id={`grad-${type.replace(' ', '')}`} x1="0" y1="0" x2="0" y2="1">
                                                    <stop offset="5%" stopColor={color} stopOpacity={0.3}/><stop offset="95%" stopColor={color} stopOpacity={0}/>
                                                </linearGradient>
                                            ))}
                                        </defs>
                                        <CartesianGrid strokeDasharray="3 3" vertical={false} stroke="#f1f5f9" />
                                        <XAxis dataKey="label" tick={{fontSize: 10}} />
                                        <YAxis allowDecimals={false} tick={{fontSize: 10}} label={{ value: 'Aprobaciones', angle: -90, position: 'insideLeft', fontSize: 10 }} />
                                        <Tooltip />
                                        <Legend onClick={(o) => setActiveType(activeType === o.dataKey ? null : o.dataKey)} />
                                        {Object.entries(TYPE_COLORS).map(([type, color]) => (
                                            <Area key={type} type="monotone" dataKey={type} stroke={color} fill={`url(#grad-${type.replace(' ', '')})`} hide={activeType !== null && activeType !== type} />
                                        ))}
                                    </AreaChart>
                                </ResponsiveContainer>
                            </div>
                        </div>
                    </div>
                </div>
            ) : (
                <div className="space-y-6 animate-fadeIn">
                    <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-5 gap-3">
                        <KPICard title="Requeridos" value={overviewKPIs.total} icon={FileText} color="indigo" sub="Universo Total" />
                        <KPICard title="Tasa Cumplimiento" value={`${overviewKPIs.percent}%`} icon={Zap} color="green" sub="Avance a Meta" />
                        <KPICard title="Eventos Re-trabajo" value={dynamicMetrics.totalReworks} icon={Repeat} color="amber" sub="Ajustes realizados" />
                        <KPICard title="Rechazos acumulados" value={dynamicMetrics.totalRejections} icon={History} color="amber" sub="Acciones de rechazo" />
                        <KPICard title="Días Ciclo Promedio" value={dynamicMetrics.heatmapData.length > 0 ? (dynamicMetrics.heatmapData.reduce((a,b) => a+b.avg, 0) / dynamicMetrics.heatmapData.length).toFixed(1) : '-'} icon={Timer} color="slate" sub="Respuesta Global" />
                    </div>
                    <div className="grid grid-cols-1 lg:grid-cols-3 gap-6">
                        <div className="lg:col-span-2 bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                             <h3 className="text-sm font-bold text-slate-700 uppercase mb-2 flex items-center gap-2"><Timer size={16} /> Mapa de Calor: Tiempo de Ciclo</h3>
                             <p className="text-[10px] text-slate-400 mb-6 uppercase font-bold tracking-wider">Días promedio de permanencia. Colores intensos indican cuellos de botella.</p>
                             <div className="h-[400px]">
                                <ResponsiveContainer width="100%" height="100%">
                                    <ScatterChart margin={{ top: 20, right: 20, bottom: 20, left: 20 }}>
                                        <CartesianGrid strokeDasharray="3 3" />
                                        <XAxis dataKey="state" type="category" name="Estado" tick={{fontSize: 9}} />
                                        <YAxis dataKey="analyst" type="category" name="Analista" tick={{fontSize: 9}} />
                                        <ZAxis dataKey="avg" range={[50, 800]} name="Días Promedio" />
                                        <Tooltip cursor={{ strokeDasharray: '3 3' }} content={(props: any) => {
                                            if (props.active && props.payload && props.payload.length) {
                                                const data = props.payload[0].payload;
                                                return (
                                                    <div className="bg-slate-800 text-white p-3 rounded-lg shadow-xl text-xs border border-slate-700">
                                                        <p className="font-bold border-b border-slate-600 pb-1 mb-1">{data.analyst}</p>
                                                        <p><span className="opacity-70">Estado:</span> {data.state}</p>
                                                        <p><span className="opacity-70">Promedio:</span> <b className="text-indigo-400">{data.avg} días</b></p>
                                                        <p><span className="opacity-70">Eventos:</span> {data.count}</p>
                                                    </div>
                                                );
                                            }
                                            return null;
                                        }} />
                                        <Scatter name="Ciclo" data={dynamicMetrics.heatmapData}>
                                            {dynamicMetrics.heatmapData.map((entry: any, index: number) => (
                                                <Cell key={index} fill={entry.avg > 15 ? '#ef4444' : entry.avg > 7 ? '#f59e0b' : '#3b82f6'} fillOpacity={0.8} />
                                            ))}
                                        </Scatter>
                                    </ScatterChart>
                                </ResponsiveContainer>
                             </div>
                        </div>
                        <div className="bg-white p-6 rounded-xl shadow-sm border border-slate-200">
                            <h3 className="text-sm font-bold text-slate-700 uppercase mb-4 flex items-center gap-2"><Repeat size={16} /> Flujo de Transiciones</h3>
                            <div className="space-y-4">
                                {dynamicMetrics.flowSummary.length > 0 ? dynamicMetrics.flowSummary.map((t, i) => (
                                    <div key={i} className="group">
                                        <div className="flex justify-between text-xs mb-1.5">
                                            <span className="font-medium text-slate-600">{t.name}</span>
                                            <span className="font-bold text-slate-900">{t.value} docs</span>
                                        </div>
                                        <div className="w-full bg-slate-100 rounded-full h-2 overflow-hidden">
                                            <div className="bg-indigo-500 h-2 rounded-full transition-all group-hover:bg-indigo-600" style={{ width: `${(t.value / Math.max(...dynamicMetrics.flowSummary.map(x=>x.value))) * 100}%` }}></div>
                                        </div>
                                    </div>
                                )) : <div className="flex flex-col items-center justify-center py-12 text-slate-400 italic text-xs">Sin datos aún.</div>}
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

const KPICard = ({ title, value, icon: Icon, color, sub, onClick, canClick }: any) => {
    const colorClasses: Record<string, string> = { 
        indigo: 'bg-indigo-50 text-indigo-600 border-indigo-100', 
        green: 'bg-green-50 text-green-600 border-green-100',
        amber: 'bg-amber-50 text-amber-600 border-amber-100',
        slate: 'bg-slate-50 text-slate-600 border-slate-100'
    };
    return (
        <div onClick={canClick ? onClick : undefined} className={`p-4 rounded-xl border shadow-sm flex flex-col justify-between ${colorClasses[color] || colorClasses.indigo} ${canClick ? 'cursor-pointer hover:shadow-md transition-all active:scale-95' : ''}`}>
            <div className="flex justify-between items-start mb-2"><span className="text-xs font-bold uppercase tracking-wider opacity-70">{title}</span><Icon size={18} /></div>
            <div><span className="text-2xl font-bold">{value}</span><div className="flex justify-between items-center mt-1"><p className="text-[10px] opacity-80 font-medium">{sub}</p>{canClick && <ArrowRight size={12} className="opacity-60" />}</div></div>
        </div>
    );
};

export default Reports;
